def _key(path: str) -> str:
    """Converte /tmp/brauna_hp_cenario.json → brauna:hp_cenario"""
    name = os.path.basename(path).replace("brauna_", "").replace(".json", "")
    return f"brauna:{name}"

def _load(path, default):
    kv = _kv_client()
    if kv:
        try:
            val = kv.get(_key(path))
            if val is not None:
                return json.loads(val) if isinstance(val, str) else val
        except Exception:
            pass
    # Fallback: arquivo local /tmp (para desenvolvimento)
    try:
        with open(path, encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return default

def _save(path, data):
    kv = _kv_client()
    if kv:
        try:
            kv.set(_key(path), json.dumps(data, ensure_ascii=False))
            return
        except Exception:
            pass
    # Fallback: arquivo local /tmp
    try:
        os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False, indent=2)
    except Exception:
        pass

# ── Carteira de referência (gestora escolhida pelo assessor) ────────────────────
# Ordem de risco comum p/ mapear perfil do cliente -> perfil disponível na gestora.
_RISCO_ORDEM = {"super_conservadora":0,"conservadora":1,"moderada":2,"arrojada":3,"agressiva":4,"super_agressiva":5}

def _mapear_perfil(perfil, perfis_disp):
    """Mapeia o perfil do cliente para o perfil mais próximo disponível na gestora.
    Ex.: 'arrojada' (não existe na gestora) -> nearest entre os perfis cadastrados."""
    perfis_disp = list(perfis_disp or [])
    if perfil in perfis_disp:
        return perfil
    if not perfis_disp:
        return perfil
    alvo = _RISCO_ORDEM.get(perfil, 2)
    # menor distância; empate -> perfil de maior risco
    return min(perfis_disp, key=lambda p: (abs(_RISCO_ORDEM.get(p, 2) - alvo), -_RISCO_ORDEM.get(p, 2)))

def _portfolios_validos(port):
    """True se o portfolios tem ao menos um perfil com alocação > 0.
    Evita que um 'Publicar' com editor vazio sobrescreva o modelo com zeros."""
    if not isinstance(port, dict):
        return False
    perfis = port.get("perfis", {}) or {}
    for p in perfis.values():
        if isinstance(p, dict) and any(isinstance(v, (int, float)) and v > 0
                                       for k, v in p.items() if k != "label"):
            return True
    return False

def _modelo_gestora(gestora_id, perfil):
    """Retorna o modelo (alocação por classe) da gestora escolhida para o perfil.
    Retorna None se a gestora não existe, chamador deve cair p/ o modelo Levante."""
    if not gestora_id:
        return None
    g = _load(_HP_GESTORAS2_FILE, {}).get(gestora_id)
    if not g:
        return None
    perfis = g.get("perfis", {}) or {}
    pk = _mapear_perfil(perfil, list(perfis.keys()))
    return {
        "modelo":     perfis.get(pk, {}) or {},
        "perfil_key": pk,
        "nome":       g.get("nome", ""),
        "referencia": g.get("referencia", "") or g.get("nome", ""),
    }

# ── Base de Conhecimento: armazenamento por-documento (escala p/ 200+ arquivos) ─
# Índice leve (metadados) num registro; texto completo de cada doc num registro próprio.
import re as _re_kb

def _know_doc_key(doc_id: str) -> str:
    return f"brauna:hp_know_doc:{doc_id}"

def _know_doc_path(doc_id: str) -> str:
    return f"/tmp/brauna_hp_know_doc_{doc_id}.json"

_KNOW_IDS_KEY = "brauna:hp_know_ids"   # SET com os ids dos documentos

def _know_meta_key(doc_id: str) -> str:
    return f"brauna:hp_know_meta:{doc_id}"

def _extrair_tickers(texto: str):
    """Extrai tickers B3 (ex: PETR4, BBAS3, KNRI11) para busca rápida sem ler o texto todo."""
    achados = set(_re_kb.findall(r"\b[A-Z]{4}\d{1,2}\b", (texto or "").upper()))
    return sorted(achados)

# ── Carteiras recomendadas (upload no Head) ──────────────────────────────────────
_FUND_STOP = {"FIC", "FIM", "FIRF", "FI", "FIF", "ADVISORY", "XP", "SEG", "SEGUROS",
              "PREV", "MASTER", "RL", "CP", "DE", "DA", "DO", "FUNDO", "II", "III",
              "ICATU", "SA", "S.A", "CIC", "MULTIMERCADO", "ACOES", "AÇÕES"}
def _norm_nome(s):
    """Chave normalizada de um nome de fundo: tokens significativos em maiúsculo."""
    u = re.sub(r"[^A-ZÀ-Ú0-9 ]", " ", (s or "").upper())
    toks = [t for t in u.split() if t not in _FUND_STOP and len(t) > 1]
    return " ".join(toks)

def _parse_carteira_rec(texto, nome=""):
    """Extrai itens recomendados de um PDF de carteira/research: tickers (RV/FII) e
    nomes de fundos; detecta o tipo. Não inventa, só o que o texto traz."""
    up = (texto or "").upper()
    tickers = _extrair_tickers(texto)
    fii   = [t for t in tickers if t.endswith("11")]
    acoes = [t for t in tickers if t[-1] in "3456" and not t.endswith("11")]
    nomes = []
    for ln in (texto or "").split("\n"):
        s = ln.strip()
        if 6 < len(s) < 80 and re.search(r"\b(FIC|FIM|FIRF|Advisory|Prev|Master|Multimercado|Crédito|Cr[eé]dito)\b", s) \
           and not re.match(r"^[\d%R\$]", s):
            nomes.append(s)
    nomes = list(dict.fromkeys(nomes))[:80]
    # Pesos por ticker: percentual na MESMA linha do ticker (peso-alvo da carteira).
    pesos = {}
    _tset = set(tickers)
    for ln in (texto or "").split("\n"):
        mt = re.search(r"\b([A-Z]{4}\d{1,2})\b", ln)
        if not mt:
            continue
        tk = mt.group(1).upper()
        if tk not in _tset or tk in pesos:
            continue
        mp = re.search(r"(\d{1,2}(?:[.,]\d{1,2})?)\s*%", ln)
        if mp:
            try:
                w = float(mp.group(1).replace(",", "."))
                if 0 < w <= 100:
                    pesos[tk] = w
            except Exception:
                pass
    if len(fii) >= 4:
        tipo = "fii"
    elif len(acoes) >= 4:
        tipo = "acoes"
    elif re.search(r"CDB|NTN|DEB[EÊ]NTURE|INDEXADOR|VENCIMENTO|TESOURO|LCI|LCA|CRI|CRA", up):
        tipo = "rf"
    elif nomes:
        tipo = "fundos"
    elif re.search(r"ALOCA[ÇC][ÃA]O|CLASSE DE ATIVO|CARTEIRA RECOMENDADA", up):
        tipo = "alocacao"
    else:
        tipo = "outro"
    return {"tipo": tipo, "tickers": tickers, "fii": fii, "acoes": acoes, "nomes": nomes, "pesos": pesos}

def _recomendados():
    """(tickers:set, nomes:set) recomendados de todas as carteiras salvas (cacheado leve)."""
    tks, nomes = set(), set()
    for c in _load(_HP_CARTEIRAS_REC_FILE, []):
        for t in c.get("tickers", []):
            tks.add(t.upper())
        for nm in c.get("nomes", []):
            k = _norm_nome(nm)
            if k:
                nomes.add(k)
    return tks, nomes

def _eh_recomendado(nome_produto, tks, nomes):
    u = (nome_produto or "").upper()
    if any(t in u for t in tks):
        return True
    key = _norm_nome(nome_produto).split()
    if len(key) >= 2:
        alvo = key[:2]
        for n in nomes:
            nt = n.split()
            if len(nt) >= 2 and nt[:2] == alvo:
                return True
    return False

def load_know_index():
    """Metadados de todos os docs. Usa SET de ids + chave de meta por doc (atômico,
    sem corrida de leitura-modificação-gravação). Cai p/ /tmp em dev local."""
    kv = _kv_client()
    if kv:
        try:
            ids = list(kv.smembers(_KNOW_IDS_KEY) or [])
        except Exception:
            ids = None
        if ids is not None:
            metas = []
            # Lê em lotes pequenos; falha de um item nunca zera a lista toda
            for inicio in range(0, len(ids), 25):
                lote = ids[inicio:inicio+25]
                keys = [_know_meta_key(i) for i in lote]
                try:
                    vals = kv.mget(*keys)
                except Exception:
                    vals = []
                    for k in keys:
                        try:
                            vals.append(kv.get(k))
                        except Exception:
                            vals.append(None)
                for v in vals:
                    if not v:
                        continue
                    try:
                        m = json.loads(v) if isinstance(v, str) else v
                        if isinstance(m, dict):
                            metas.append(m)
                    except Exception:
                        continue
            metas.sort(key=lambda m: m.get("ts", 0), reverse=True)
            return metas
    return _load(_HP_KNOW_FILE, [])

def add_know_meta(meta: dict):
    """Adiciona um documento ao índice de forma atômica (SET próprio + SADD)."""
    kv = _kv_client()
    if kv:
        try:
            kv.set(_know_meta_key(meta["id"]), json.dumps(meta, ensure_ascii=False))
            kv.sadd(_KNOW_IDS_KEY, meta["id"])
            return
        except Exception:
            pass
    idx = _load(_HP_KNOW_FILE, [])
    idx.insert(0, meta)
    _save(_HP_KNOW_FILE, idx)

def update_know_meta(doc_id: str, **changes):
    """Atualiza campos do meta de um doc (ex: marcar publicado)."""
    kv = _kv_client()
    if kv:
        try:
            v = kv.get(_know_meta_key(doc_id))
            if v is not None:
                m = json.loads(v) if isinstance(v, str) else v
                m.update(changes)
                kv.set(_know_meta_key(doc_id), json.dumps(m, ensure_ascii=False))
                return True
        except Exception:
            pass
    idx = _load(_HP_KNOW_FILE, [])
    for m in idx:
        if m.get("id") == doc_id:
            m.update(changes)
    _save(_HP_KNOW_FILE, idx)
    return True

def delete_know_meta(doc_id: str):
    kv = _kv_client()
    if kv:
        try:
            kv.srem(_KNOW_IDS_KEY, doc_id)
            kv.delete(_know_meta_key(doc_id))
            return
        except Exception:
            pass
    idx = [m for m in _load(_HP_KNOW_FILE, []) if m.get("id") != doc_id]
    _save(_HP_KNOW_FILE, idx)

def load_know_text(doc_id: str) -> str:
    """Texto completo de um documento. Tenta registro próprio; cai p/ texto embutido (formato antigo)."""
    kv = _kv_client()
    if kv:
        try:
            val = kv.get(_know_doc_key(doc_id))
            if val is not None:
                d = json.loads(val) if isinstance(val, str) else val
                return d.get("texto", "") if isinstance(d, dict) else (d or "")
        except Exception:
            pass
    # Fallback /tmp
    try:
        with open(_know_doc_path(doc_id), encoding="utf-8") as f:
            return json.load(f).get("texto", "")
    except Exception:
        pass
    # Compatibilidade: texto ainda embutido no índice (docs antigos)
    for d in load_know_index():
        if d.get("id") == doc_id and d.get("texto"):
            return d["texto"]
    return ""

def save_know_text(doc_id: str, texto: str) -> bool:
    """Grava o texto completo do doc. Retorna True se persistiu no KV (durável).
    Em produção (Vercel) o /tmp é efêmero: gravar só lá significa perder o texto no
    próximo cold start, gerando doc com meta mas sem texto. Quem chama deve abortar
    a criação do meta se o KV estava configurado mas a gravação não foi durável."""
    payload = {"id": doc_id, "texto": texto}
    kv = _kv_client()
    if kv:
        try:
            kv.set(_know_doc_key(doc_id), json.dumps(payload, ensure_ascii=False))
            return True
        except Exception:
            pass  # cai p/ /tmp, mas sinaliza que NÃO foi durável
    try:
        with open(_know_doc_path(doc_id), "w", encoding="utf-8") as f:
            json.dump(payload, f, ensure_ascii=False)
    except Exception:
        pass
    return False

def delete_know_text(doc_id: str):
    kv = _kv_client()
    if kv:
        try:
            kv.delete(_know_doc_key(doc_id))
        except Exception:
            pass
    try:
        os.remove(_know_doc_path(doc_id))
    except Exception:
        pass

