# ── SAA, alocação-alvo por perfil (régua do rebalanceamento; casa = Braúna) ──────
_SAA_JSON_CACHE = None
def _saa_json():
    global _SAA_JSON_CACHE
    if _SAA_JSON_CACHE is None:
        try:
            with open(os.path.join(ROOT, "saa_referencia.json"), encoding="utf-8") as f:
                _SAA_JSON_CACHE = json.load(f)
        except Exception:
            _SAA_JSON_CACHE = {}
    return _SAA_JSON_CACHE

def saa_alvo(perfil, gestora="brauna"):
    """Alocação-alvo (%) por classe para o perfil, da gestora (default Braúna = casa).
    Prefere a fonte viva (Alocações de Referência editáveis no app); cai para
    saa_referencia.json. Retorna {} se não houver alvo para o perfil."""
    if not perfil:
        return {}
    # 1) fonte viva (gest2 editável), só usa se tiver soma > 0
    try:
        viva = _load(_HP_GESTORAS2_FILE, {}).get(gestora, {}).get("perfis", {}).get(perfil)
        if viva and any(float(v or 0) for v in viva.values()):
            return {k: float(v or 0) for k, v in viva.items()}
    except Exception:
        pass
    # 2) fallback: saa_referencia.json (bundlado no projeto)
    try:
        j = _saa_json().get("gestoras", {}).get(gestora, {}).get("perfis", {}).get(perfil)
        if isinstance(j, dict):
            return {k: float(v or 0) for k, v in j.items() if not str(k).startswith("_")}
    except Exception:
        pass
    return {}


# ── Prateleiras de produtos (cardápio p/ fechar gaps de alocação) ────────────────
_PRAT_CACHE = {}
def _prat(nome):
    if nome not in _PRAT_CACHE:
        try:
            with open(os.path.join(ROOT, nome), encoding="utf-8") as f:
                _PRAT_CACHE[nome] = json.load(f)
        except Exception:
            _PRAT_CACHE[nome] = {}
    return _PRAT_CACHE[nome]

def _fpct(v):
    try:
        return f"{float(v):.2f}%"
    except Exception:
        return "n/d"

def _sug_rf(filtro, obs, n, excluir=None):
    """RF tradicional (suitability Geral), isentos primeiro, depois por rating.
    Exclui o que o cliente já tem e diversifica emissor entre produtos com FGC (teto)."""
    xs = [p for p in _prat("rf_tradicional_br.json").get("produtos", [])
          if (p.get("publico") or "").startswith("Investidor Geral") and filtro(p)]
    xs.sort(key=lambda p: (not p.get("isento"), str(p.get("risco") or "99")))
    _vistos, _emis, sel = set(), set(), []
    for p in xs:
        at = p.get("ativo")
        if at in _vistos:                    # mesmo papel com tickers diferentes
            continue
        _vistos.add(at)
        if excluir and (at or "").upper() in excluir:
            continue
        if p.get("fgc"):                     # diversifica emissor só entre bancários (teto FGC)
            ek = " ".join((at or "").split()[:2]).upper()
            if ek in _emis:
                continue
            _emis.add(ek)
        sel.append(p)
        if len(sel) >= n:
            break
    out = []
    for p in sel:
        det = p.get("tax_max") or p.get("tax_min") or ""
        if p.get("isento") and p.get("grossup_max"):
            det = f"{det} · isento (≈{p['grossup_max']} bruto)"
        out.append({"nome": p.get("ativo"), "detalhe": det, "fonte": "RF XP",
                    "fgc": p.get("fgc"), "obs": obs})
    return out

def _sug_fund(classes, obs, n, excluir=None):
    """Fundos (suitability Geral), prioriza track record 24/36m e menor taxa
    (evita 'chasing' do 12m); exclui o que o cliente já tem."""
    def _base(p):
        for k in ("rent_36m", "rent_24m", "rent_12m"):
            v = p.get(k)
            if isinstance(v, (int, float)):
                return v, (k != "rent_12m")
        return None, False
    cand = []
    for p in _prat("fundos_xp.json").get("fundos", []):
        if p.get("investidor") not in (None, "", "Geral"):
            continue
        if p.get("xp_class") not in classes:
            continue
        if excluir and (p.get("nome") or "").upper() in excluir:
            continue
        b, tem_track = _base(p)
        if b is None:
            continue
        adm = p.get("taxa_adm") or 0
        cand.append((1 if tem_track else 0, b - adm * 2, p))   # track longo + custo
    cand.sort(key=lambda t: (t[0], t[1]), reverse=True)
    return [{"nome": p.get("nome"),
             "detalhe": f"36m {_fpct(p.get('rent_36m'))} · 24m {_fpct(p.get('rent_24m'))} · adm {_fpct(p.get('taxa_adm'))}",
             "fonte": "Fundo XP", "obs": obs} for _, __, p in cand[:n]]

def _sug_intl(n, excluir=None):
    xs = [p for p in _prat("rf_internacional.json").get("produtos", [])
          if p.get("tipo") in ("treasury", "bond") and isinstance(p.get("rentab_aa"), (int, float))
          and not (excluir and (p.get("ativo") or "").upper() in excluir)]
    # Treasuries (soberano) primeiro, núcleo conservador; depois bonds por yield.
    xs.sort(key=lambda p: (p.get("tipo") != "treasury", -(p.get("rentab_aa") or 0)))
    return [{"nome": f"{p.get('ativo')} ({p.get('vencimento')})",
             "detalhe": f"{_fpct(p.get('rentab_aa'))} a.a. USD · {p.get('rating') or ''}".strip(" ·"),
             "fonte": "RF Intl", "obs": "15% anual (Lei 14.754)"} for p in xs[:n]]

def _sug_cetip(filtro, obs, n, excluir=None):
    xs = [f for f in _prat("fundos_cetipados.json").get("fundos", [])
          if filtro(f) and not (excluir and (f.get("ticker") or "").upper() in excluir)]
    xs.sort(key=lambda f: -(f.get("dy_aa") or 0))
    return [{"nome": f.get("ticker"), "detalhe": f"DY {_fpct(f.get('dy_aa'))} · {f.get('categoria')}",
             "fonte": "Cetipado", "obs": obs} for f in xs[:n]]

def _travas_institucionais(cls, gap_valor, auc, prods_prat):
    """Tetos do Controle Institucional de Alocação XP (vigência ago/2026), NUNCA exceder.
    Retorna a lista de avisos aplicáveis à sugestão desta classe. Ver memória
    'limites-alocacao-institucional-xp'. AUC aqui = patrimônio da carteira (proxy;
    o AUC oficial soma todas as marcas XP + OPIN)."""
    import re as _re
    travas = []
    if not auc or auc <= 0:
        return travas
    def _brl(v): return f"R$ {v:,.0f}".replace(",", ".")
    top   = (prods_prat or [{}])[0]
    nome  = (top.get("nome") or "").upper()
    is_tesouro = any(w in nome for w in ("NTN", "TESOURO", "LTN", "LFT"))
    # Emissão BANCÁRIA (risco de banco, com FGC): CDB, LCI, LCA, LC, RDB, LF.
    is_banco = bool(top.get("fgc")) or bool(_re.search(r"\b(CDB|LCI|LCA|RDB|LC|LF|LETRA\s+FINANCEIRA)\b", nome))
    # Crédito PRIVADO (dívida de empresa não-financeira, sem FGC): debênture, CRI, CRA,
    # nota comercial, FIDC. NÃO inclui emissão bancária nem título público.
    is_cred_priv = (not is_banco and not is_tesouro) and bool(
        _re.search(r"\b(DEB[ÊE]NTURE|CRI|CRA|NOTA\s+COMERCIAL|FIDC|CDCA|CDA)\b", nome))
    # 1) Crédito privado, máx 5% do AUC por emissor
    if is_cred_priv:
        lim = 0.05 * auc
        if gap_valor > lim:
            n = int(gap_valor // lim) + (1 if gap_valor % lim else 0)
            travas.append(f"Crédito privado: máx 5% do AUC ({_brl(lim)}) por emissor, dividir em ~{n} emissores.")
    # 2) NTN-B com vencimento ≥ 2040, máx 15% do AUC
    if is_tesouro and "NTN" in nome:
        m = _re.search(r"(20\d{2})", nome)
        if m and int(m.group(1)) >= 2040:
            travas.append(f"NTN-B ≥2040: concentração máx 15% do AUC ({_brl(0.15*auc)}).")
    # 3) Emissão bancária, FGC cobre até R$ 250k por emissor/conglomerado
    if is_banco and gap_valor > 250000:
        n = int(gap_valor // 250000) + (1 if gap_valor % 250000 else 0)
        travas.append(f"Emissão bancária: FGC cobre até R$ 250k por emissor/conglomerado, dividir em ~{n} emissores para manter a cobertura (se high yield, teto de R$ 180k).")
    return travas

def _sugerir_por_classe(cat, n=3, excluir=None):
    """Retorna até n produtos da prateleira adequados para a classe subalocada.
    `excluir` = conjunto de nomes/tickers (UPPER) que o cliente já tem, para não repetir."""
    up = lambda s: (s or "").upper()
    if cat == "pos_fixado":
        return _sug_rf(lambda p: "CDI" in up(p.get("indexador")) and p.get("fgc"),
                       "Carrego pós-fixado; com FGC. Comparar líquido (isento vence tributável).", n, excluir)
    if cat == "inflacao":
        r = _sug_rf(lambda p: "IPC" in up(p.get("indexador")), "Proteção inflacionária (IPCA+).", n, excluir)
        return r or _sug_cetip(lambda f: f.get("exposicao", {}).get("IPCA", 0) >= 50,
                               "FII Infra/imobiliário IPCA, atenção à liquidez.", n, excluir)
    if cat == "pre_fixado":
        return _sug_rf(lambda p: "PRÉ" in up(p.get("indexador")) or "PREF" in up(p.get("indexador")),
                       "Prefixado tático; aceita marcação a mercado.", n, excluir)
    if cat == "acoes":
        return _sug_fund(["Renda Variável Long Only", "Renda Variável Long Biased"],
                         "Ações via fundo; IR 15% no resgate, sem come-cotas.", n, excluir)
    if cat == "fiis":
        return _sug_cetip(lambda f: "FII" in up(f.get("exposicao", {}) and "") or f.get("categoria") in ("Fundos Imobiliários", "FII Infra"),
                          "FII, renda; rendimento isento PF (requisitos).", n, excluir) \
               or _sug_fund(["Fundo Listado"], "FII/listados via fundo.", n, excluir)
    if cat == "multimercado":
        return _sug_fund(["Macro Alta Vol", "Macro Média Vol", "Multiestratégia", "Macro Baixa Vol"],
                         "Multimercado; come-cotas semestral. Precisa justificar risco vs CDI.", n, excluir)
    if cat == "internacional":
        return _sug_intl(n, excluir) or _sug_fund(["Internacional Ações Hedgeado", "Internacional Renda Fixa"],
                                         "Internacionalização; 15% anual no exterior.", n, excluir)
    if cat == "alternativos":
        return _sug_fund(["Alternativo Ilíquido", "Multiestratégia"],
                         "Alternativos; prêmio de iliquidez, checar prazo/suitability.", n, excluir)
    return []

def sugestoes_realocacao(comp, perfil, max_classes=3, por_classe=3):
    """Para as classes mais subalocadas vs SAA Braúna, sugere produtos da prateleira
    (suitability Geral) com nota de tributação. Retorna [] se não houver SAA p/ o perfil."""
    alvo = saa_alvo(perfil)
    if not alvo:
        return []
    tks, nomes = _recomendados()
    gaps = [(cat, alvo.get(cat, 0) - comp.get(cat, 0)) for cat in CATS]
    gaps = sorted([g for g in gaps if g[1] >= 5], key=lambda x: -x[1])
    out = []
    for cat, gap in gaps[:max_classes]:
        cand = _sugerir_por_classe(cat, max(por_classe * 3, 8))
        for p in cand:
            p["recomendado"] = _eh_recomendado(p.get("nome"), tks, nomes)
        cand.sort(key=lambda p: not p.get("recomendado"))  # recomendados primeiro (ordenação estável)
        prods = cand[:por_classe]
        if prods:
            out.append({"classe": cat, "label": LABELS.get(cat, cat),
                        "gap_pct": round(gap, 1), "produtos": prods})
    return out


