def _objetivos_seed():
    """Lê o seed versionado no repo (objetivos_okr.json). Serve de base na 1ª carga."""
    try:
        with open(os.path.join(ROOT, "objetivos_okr.json"), encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {"_meta": {}, "assessores": []}

def carregar_objetivos():
    """Estado editável dos objetivos. Persistido no KV/tmp; se vazio, cai no seed do repo.
    Mescla o seed para preservar metadados (ROA/labels) mesmo após edições."""
    seed = _objetivos_seed()
    salvo = _load(_OBJETIVOS_FILE, None)
    if not salvo or not isinstance(salvo, dict) or not salvo.get("assessores"):
        return seed
    # Mantém sempre o _meta do seed (ROA/labels) e usa os assessores salvos
    salvo["_meta"] = {**seed.get("_meta", {}), **salvo.get("_meta", {}),
                      "roa": seed.get("_meta", {}).get("roa", {}),
                      "labels": seed.get("_meta", {}).get("labels", {})}
    return salvo


def buscar_macro_bcb():
    try:
        import urllib.request
        def bcb(serie):
            url = f"https://api.bcb.gov.br/dados/serie/bcdata.sgs.{serie}/dados/ultimos/1?formato=json"
            with urllib.request.urlopen(url, timeout=5) as r:
                return json.loads(r.read())[0]["valor"]
        return {
            "selic_meta": float(bcb(432).replace(",",".")),
            "ipca_12m":   float(bcb(13522).replace(",",".")),
        }
    except Exception:
        return {"selic_meta": None, "ipca_12m": None}


def mapear(texto):
    t = texto.lower().strip()
    for k, v in MAPEAMENTO.items():
        if k in t:
            return v
    return None


def extrair_composicao(pdf_bytes):
    import pdfplumber
    texto = ""
    with pdfplumber.open(io.BytesIO(pdf_bytes)) as pdf:
        for p in pdf.pages:
            texto += (p.extract_text() or "") + "\n"

    comp = {c: 0.0 for c in CATS}
    comp["caixa"] = 0.0
    padrao = re.compile(r"([A-Za-zÀ-ÿ\s\-\/]+?)\s+(?:R\$[\s\d\.,]+\s+)?(\d{1,3}(?:[.,]\d{1,3})*(?:[.,]\d{1,2})?)\s*%", re.IGNORECASE)
    for linha in texto.splitlines():
        m = padrao.search(linha.strip())
        if m:
            try:
                perc = float(m.group(2).replace(".", "").replace(",", "."))
            except ValueError:
                continue
            cat = mapear(m.group(1).strip())
            if cat and perc > 0:
                comp[cat] = comp.get(cat, 0.0) + perc

    rent = {}
    mp = re.search(r"Portf.lio\s+([\d,]+)%\s+([\d,]+)%\s+([\d,]+)%\s+([\d,]+)%", texto)
    mc = re.search(r"CDI\s+([\d,]+)%\s+([\d,]+)%\s+([\d,]+)%\s+([\d,]+)%", texto)
    if mp: rent["portfolio"] = {k: float(mp.group(i+1).replace(",",".")) for i,k in enumerate(["mes","ano","12m","24m"])}
    if mc: rent["cdi"]       = {k: float(mc.group(i+1).replace(",",".")) for i,k in enumerate(["mes","ano","12m","24m"])}

    patrimonio = 0.0
    mp2 = re.search(r"PATRIM.NIO TOTAL BRUTO:\s*R\$\s*([\d\.,]+)", texto)
    if mp2:
        try: patrimonio = float(mp2.group(1).replace(".","").replace(",","."))
        except: pass

    caixa = comp.pop("caixa", 0.0)
    total = sum(comp.values())
    if total > 1:
        fator = 100.0 / total
        comp = {k: round(v * fator, 2) for k, v in comp.items()}
    return comp, caixa, rent, patrimonio


def _parse_ret_classe(texto):
    """Extrai o retorno realizado por classe (Mês/Ano/12M/24M) + saldo bruto da
    tabela 'ESTRATÉGIA: COMPOSIÇÃO' do XPerformance. Base do comparativo Cliente ×
    Recomendada. Retorna {cls: {saldo, mes, ano, "12m", "24m"}}."""
    MAP = [
        (r"p.s\s*fix", "pos_fixado"), (r"pr.\s*fix", "pre_fixado"),
        (r"infla", "inflacao"), (r"renda\s*vari.vel\s*brasil", "acoes"),
        (r"fundos?\s*listad", "fiis"), (r"multimercad", "multimercado"),
        (r"renda\s*fixa\s*global", "internacional"), (r"internacion", "internacional"),
        (r"alternativ", "alternativos"), (r"cripto", "criptomoedas"),
    ]
    def _cls(n):
        n = n.lower()
        for pat, c in MAP:
            if re.search(pat, n):
                return c
        return None
    def _num(s):
        s = s.strip().replace("%", "")
        if s in ("-", "", "–", "n/d"):
            return None
        try:
            return float(s.replace(".", "").replace(",", "."))
        except Exception:
            return None
    # nome (pct%) R$ saldo  <mes> <ano> <12m> <24m> , .match tolera lixo antes (ex.: "% total investido")
    linha = re.compile(r"(.*?)\((\d[\d,]*)%\)\s+R\$\s*([\d\.]+,\d{2})\s+(.+)")
    out = {}
    for l in texto.splitlines():
        m = linha.match(l.strip())
        if not m:
            continue
        nome, _pct, saldo_s, resto = m.groups()
        cls = _cls(nome)
        if not cls:
            continue
        try:
            saldo = float(saldo_s.replace(".", "").replace(",", "."))
        except Exception:
            continue
        vals = {}
        for per, tk in zip(["mes", "ano", "12m", "24m"], resto.split()[:4]):
            vals[per] = _num(tk)
        if cls in out:
            # mesma classe em 2 linhas (ex.: Renda Fixa Global + Internacional): pondera por saldo
            prev = out[cls]
            ns = prev["saldo"] + saldo
            for per in ["mes", "ano", "12m", "24m"]:
                a, b = prev.get(per), vals.get(per)
                if a is not None and b is not None:
                    prev[per] = (a * prev["saldo"] + b * saldo) / ns if ns else a
                elif b is not None:
                    prev[per] = b
            prev["saldo"] = ns
        else:
            out[cls] = {"saldo": saldo, **vals}
    return out


_POS_CLASSE_MAP = [
    (r"^P[oó]s\s*Fix",            "pos_fixado"),
    (r"^Infla",                   "inflacao"),
    (r"^Pr[eé]\s*Fix",            "pre_fixado"),
    (r"^Multi.?mercado",          "multimercado"),
    (r"^Renda\s*Vari[aá]vel",     "acoes"),
    (r"^Fundos\s*Listados",       "fiis"),
    (r"^Renda\s*Fixa\s*Global",   "internacional"),
    (r"^Internacion",             "internacional"),
    (r"^Alternativ",              "alternativos"),
    (r"^Cripto",                  "criptomoedas"),
]
_POS_CAIXA_HDR = re.compile(r"^(Caixa|Proventos)\b", re.I)
_POS_RUIDO = re.compile(r"^(CP\s*RL|RF\s*RL|RF\s*CP|CP\s*LP|CDI|RL|RF|CP|Limitada|Resp|LP)$", re.I)
_POS_NUM_LINE = re.compile(r"R\$\s*([\d\.]+,\d{2})\s+(-|[\d\.]+)\s+(-?[\d\.,]+%.*)$")
_POS_TICKER = re.compile(r"^([A-Z]{4}\d{1,2})\b")

def _parse_posicao_detalhada(texto):
    """Lê a tabela 'POSIÇÃO DETALHADA DOS ATIVOS' do XPerformance.
    Colunas por ativo: Saldo Bruto | Qtd | %Aloc | Rent.Mês %CDI | Rent.Ano %CDI | Rent.24M %CDI.
    Retorna lista de dicts {nome,ticker,classe,saldo,qtd,perc,rent_mes,rent_ano,rent_24m}.
    Cabeçalho de classe tem Qtd='-'; retorno é a rentabilidade da posição (já marcada a mercado)."""
    def _f(s):
        try: return float(s.replace(".", "").replace(",", "."))
        except Exception: return None
    def _fq(s):
        if s in ("-", None): return None
        try: return float(s)
        except Exception: return None

    em_tab = False; classe = None; nome_buf = []; ativos = []
    for raw in texto.splitlines():
        l = raw.strip()
        if not l:
            continue
        if re.search(r"POSI..O\s+DETALHADA\s+DOS\s+ATIVOS", l, re.I):
            em_tab = True; nome_buf = []; continue   # mantém a classe (tabela segue entre páginas)
        if not em_tab:
            continue
        if re.search(r"EVOLU..O|ESTRAT.GIA:", l, re.I):
            em_tab = False; classe = None; nome_buf = []; continue
        if re.search(r"Relat.rio\s+informativo", l, re.I):
            continue
        if re.match(r"^(MÊS ATUAL|Estrat.gia Saldo|.*Saldo Bruto Qtd|PRECIFICA|POSI..O DETALHADA)", l, re.I):
            continue

        m = _POS_NUM_LINE.search(l)
        if not m:
            if _POS_RUIDO.match(l):
                continue
            nome_buf.append(l)
            continue

        saldo = _f(m.group(1)); qtd = m.group(2); rest = m.group(3)
        pcts = re.findall(r"(-?[\d\.]*\d,\d+)%", rest)
        antes = l[:m.start()].strip()
        if qtd == "-":                                  # cabeçalho de classe
            base = antes or (nome_buf[-1] if nome_buf else "")
            alvo = None
            for pat, cls in _POS_CLASSE_MAP:
                if re.search(pat, base, re.I):
                    alvo = cls; break
            if alvo is None and _POS_CAIXA_HDR.match(base):
                alvo = "_skip"
            classe = alvo; nome_buf = []; continue

        nome = antes if antes else " ".join(nome_buf).strip()
        nome_buf = []
        nome = re.sub(r"\s+(CP\s*RL|RF\s*RL|RF\s*CP|CP\s*LP|RL|RF|CP)$", "", nome).strip()
        if classe in (None, "_skip") or not nome or saldo is None:
            continue
        mt = _POS_TICKER.match(nome)
        ativos.append({
            "nome": nome, "ticker": (mt.group(1) if mt else None), "classe": classe,
            "saldo": saldo, "qtd": _fq(qtd),
            "perc":     _f(pcts[0]) if len(pcts) >= 1 else None,
            "rent_mes": _f(pcts[1]) if len(pcts) >= 2 else None,
            "rent_ano": _f(pcts[3]) if len(pcts) >= 4 else None,
            "rent_24m": _f(pcts[5]) if len(pcts) >= 6 else None,
        })
    return ativos


def extrair_xperformance(pdf_bytes):
    """Parser especializado para o relatório XPerformance da XP Investimentos."""
    import pdfplumber
    texto = ""
    with pdfplumber.open(io.BytesIO(pdf_bytes)) as pdf:
        for p in pdf.pages:
            texto += (p.extract_text() or "") + "\n"

    # Dados do cabeçalho, suporta encoding com ? no lugar de acentos
    conta_m = re.search(r"Conta\s+Assessor\s+Data.*?\n(\d+)\s+(.+?)\s+(\d{2}/\d{2}/\d{4})", texto, re.DOTALL)
    conta    = conta_m.group(1).strip() if conta_m else ""
    assessor = conta_m.group(2).strip() if conta_m else ""
    data_ref = conta_m.group(3).strip() if conta_m else ""

    # Patrimônio, cabeçalho e valor podem estar em linhas separadas
    patrimonio = 0.0
    idx_pat = texto.find("TOTAL BRUTO")
    if idx_pat != -1:
        trecho = texto[idx_pat:idx_pat+400]
        pat_m = re.search(r"R\$\s*([\d]{1,3}(?:\.\d{3})*,\d{2})", trecho)
        if pat_m:
            try: patrimonio = float(pat_m.group(1).replace(".","").replace(",","."))
            except: pass

    # Rentabilidade portfolio e CDI (tabela-resumo "Referências (%)": Mês Ano 12M 24M).
    # O Portfólio pode ter "-" em 12M/24M (carteira nova) — por isso ancoramos na
    # tabela-resumo, senão a regex de 4 percentuais casava o HISTÓRICO MENSAL por engano.
    rent = {}
    def _rv(x):
        x = (x or "").strip()
        return None if x in ("-", "") else float(x.replace("%", "").replace(",", "."))
    mp = re.search(r"Refer[êe]ncias?\s*\(%\)[^\n]*\n(?:[^\n]*\n){0,6}?\s*Portf.lio\s+"
                   r"(-|[-\d,]+%)\s+(-|[-\d,]+%)\s+(-|[-\d,]+%)\s+(-|[-\d,]+%)\s*(?:\n|$)", texto)
    if not mp:  # fallback: formato antigo (4 percentuais na mesma linha)
        mp = re.search(r"Portf.lio\s+([-\d,]+%)\s+([-\d,]+%)\s+([-\d,]+%)\s+([-\d,]+%)", texto)
    mc = re.search(r"CDI\s+([-\d,]+)%\s+([-\d,]+)%\s+([-\d,]+)%\s+([-\d,]+)%", texto)
    if mp: rent["portfolio"] = {k: _rv(mp.group(i+1)) for i, k in enumerate(["mes", "ano", "12m", "24m"])}
    if mc: rent["cdi"]       = {k: float(mc.group(i+1).replace(",", ".")) for i, k in enumerate(["mes", "ano", "12m", "24m"])}

    # Composição, suporta acentos normais E substituídos por ? (encoding pdfplumber)
    # Mapa amplo: nomes como aparecem no PDF (com e sem acento)
    comp_map = [
        (r"[Pp].s\s*[Ff]ix",               "pos_fixado"),    # Pós Fixado / P?s Fixado
        (r"[Ii]nfla..[ao]",                "inflacao"),       # Inflação / Infla??o
        (r"[Pp]r.\s*[Ff]ix",               "pre_fixado"),     # Pré Fixado / Pr? Fixado
        (r"[Rr]enda\s*[Vv]ari",            "acoes"),          # Renda Variável Brasil
        (r"[Ff]undos?\s*[Ll]ist",          "fiis"),           # Fundos Listados
        (r"[Mm]ulti.?[Mm]ercado",          "multimercado"),   # Multimercado
        (r"[Aa]lternativ",                 "alternativos"),   # Alternativo
        (r"[Ii]nternacion",                "internacional"),  # Internacional
        (r"[Cc]ripto",                     "criptomoedas"),   # Cripto
        (r"[Ff]undos?\s*[Ee]strutur",      "alternativos"),   # Fundos Estruturados → alternativos
        (r"[Pp]revidên|[Pp]revid.ncia",    "pos_fixado"),     # Previdência → pós fixado
    ]
    comp = {c: 0.0 for c in CATS}
    caixa_perc = 0.0

    for linha in texto.splitlines():
        # Padrão 1: "Pós Fixado (77,79%)" ou "P?s Fixado (77,79%)"
        m = re.search(r"([\w\s\?\-\/\.]+?)\s*\((\d{1,3}[,\.]\d{1,2})%\)", linha)
        if m:
            nome_cat = m.group(1).strip()
            try: perc = float(m.group(2).replace(",","."))
            except: continue
            if re.search(r"[Cc]aixa|[Pp]rovento|100,00", nome_cat): caixa_perc = perc; continue
            for pat, key in comp_map:
                if re.search(pat, nome_cat, re.I):
                    comp[key] = max(comp[key], perc); break

    # Fallback: parser genérico se composição não encontrada
    if sum(comp.values()) < 1:
        comp, caixa_perc, rent2, pat2 = extrair_composicao(pdf_bytes)
        if not rent: rent = rent2
        if not patrimonio: patrimonio = pat2

    # ── Ativos individuais de RV e FIIs ─────────────────────────────────────────
    acoes = []
    fiis_list = []
    rv_section = False
    fii_section = False
    for linha in texto.splitlines():
        if re.search(r"Renda\s*Vari[aá]vel\s*Brasil", linha, re.I): rv_section = True; fii_section = False; continue
        if re.search(r"Fundos\s*Listados", linha, re.I): fii_section = True; rv_section = False; continue
        if re.search(r"Alternativo|Pre.Fixado|Infla|Caixa|Proventos", linha, re.I) and (rv_section or fii_section):
            rv_section = False; fii_section = False; continue

        ticker_m = re.match(r"^([A-Z]{3,5}[0-9]{1,2})\s+R\$?\s*([-\d\.,]+)\s+([\d]+)\s+([\d,]+)%", linha.strip())
        if not ticker_m:
            ticker_m = re.match(r"^([A-Z]{3,5}[0-9]{1,2})\s+([-R\$\s\d\.,]+?)\s+(\d+)\s+([\d,]+)%", linha.strip())

        if ticker_m and (rv_section or fii_section):
            ticker = ticker_m.group(1)
            try: saldo_raw = ticker_m.group(2).replace("R$","").replace(".","").replace(",",".").strip()
            except: saldo_raw = "0"
            try: saldo = float(saldo_raw)
            except: saldo = 0.0
            try: qtd = int(ticker_m.group(3).replace(".",""))
            except: qtd = 0
            try: perc = float(ticker_m.group(4).replace(",","."))
            except: perc = 0.0
            item = {"ticker": ticker, "saldo": saldo, "qtd": qtd, "perc": perc}
            if fii_section or re.match(r".*11$", ticker):
                fiis_list.append(item)
            else:
                acoes.append(item)

    # ── Ativos individuais de Renda Fixa ─────────────────────────────────────────
    # Formato na seção "POSIÇÃO DETALHADA":
    #   Cabeçalho de seção: "P?s Fixado R$ 346.922,61 - 5,72% ..."  (sem parênteses)
    #   Ativo multilinhas:   nome na linha N, "R$ saldo qtd perc% ..." na linha N+1
    #   Ativo inline (CRA/CRI): "CRA ... R$ 35.728,16 48 0,59% ..." tudo em uma linha

    RF_SECAO_MAP = [
        (r"^[Pp].s\s*[Ff]ix",      "pos_fixado"),
        (r"^[Ii]nfla..[ao]",       "inflacao"),
        (r"^[Pp]r.\s*[Ff]ix",      "pre_fixado"),
        (r"^[Mm]ulti.?[Mm]ercado", "multimercado"),
        (r"^[Ii]nternacion",       "internacional"),
        (r"^[Aa]lternativ",        "alternativos"),
    ]
    # Seção de cabeçalho: nome da classe + R$ total logo na mesma linha
    RF_HEADER_PAT = re.compile(
        r"^([A-Za-z\?\s\-]+?)\s+R\$\s+[\d\.,]+"
    )
    # Linha de dados de ativo: começa com R$ e tem qtd + %
    RF_DADOS_PAT = re.compile(
        r"R\$\s*([-\d\.]+,\d{2})\s+([-\d\.]+)\s+([-\d,]+)%\s+([-\d,]+)%"
    )
    # Para encerrar a leitura RF
    RF_FIM_PAT = re.compile(
        r"Renda\s*Vari|Fundos\s*[Ll]istados|MOVIMENTA|ESTAT.STICA\s+HIST|"
        r"HIST.RICO\s+POR\s+ESTRAT|Relat.rio\s+informativo|"
        r"POSIÇÃO DETALHADA.*POSIÇÃO", re.I
    )
    # Ruídos que aparecem depois do nome do fundo
    RF_RUIDO_PAT = re.compile(r"^(RL|RF\s*CP|CP\s*RL|RF|CP|Incentivado.*Investimento.*)$", re.I)

    def _brl(s):
        try: return float(s.replace(".","").replace(",","."))
        except: return 0.0

    rf_ativos    = []
    rf_cls       = None    # classe atual
    rf_nome_buf  = None    # nome em buffer (linha anterior)
    em_detalhe   = False   # True quando dentro de "POSIÇÃO DETALHADA"

    for linha in texto.splitlines():
        l = linha.strip()
        if not l:
            continue

        # Entra na seção de posição detalhada
        if re.search(r"POSI..O\s+DETALHADA", l, re.I):
            em_detalhe = True
            continue

        if not em_detalhe:
            continue

        # Encerra ao chegar em RV ou rodapé
        if RF_FIM_PAT.search(l):
            em_detalhe = False
            rf_cls = None
            rf_nome_buf = None
            continue

        # Detecta cabeçalho de seção RF: "P?s Fixado R$ 346.922,61 - 5,72% ..."
        nova_cls = None
        for pat, cls in RF_SECAO_MAP:
            if re.search(pat, l, re.I) and "R$" in l:
                # Confirma que é cabeçalho (tem o total da seção, não ativo individual)
                # Cabeçalhos têm " - " antes do %
                if re.search(r"R\$.*-\s*\d+[,\.]\d+%", l):
                    nova_cls = cls
                    break
        if nova_cls:
            rf_cls = nova_cls
            rf_nome_buf = None
            continue

        if rf_cls is None:
            continue

        # Linha de dados: "R$ 78.286,79 67759.84 1,29% 1,37% ..."
        m = RF_DADOS_PAT.search(l)
        if m:
            saldo    = _brl(m.group(1))
            perc_str = m.group(3)
            rent_mes_str = m.group(4)
            try: perc     = float(perc_str.replace(",","."))
            except: perc  = 0.0
            try: rent_mes = float(rent_mes_str.replace(",","."))
            except: rent_mes = None

            # Tenta pegar rent_12m (5ª % na linha)
            all_pcts = re.findall(r"([-\d,]+)%", l)
            rent_12m = float(all_pcts[4].replace(",",".")) if len(all_pcts) >= 5 else None

            # Nome: texto antes do R$ na mesma linha (CRA/CRI inline) ou buffer anterior
            before_rs = l[:m.start()].strip()
            before_rs = re.sub(r"\s+(RL|RF\s*CP|CP\s*RL|RF|CP)\s*$", "", before_rs).strip()
            nome = (before_rs or rf_nome_buf or "").strip()

            if nome and saldo > 0:
                rf_ativos.append({
                    "nome":     nome,
                    "classe":   rf_cls,
                    "saldo":    saldo,
                    "perc":     perc,
                    "rent_mes": rent_mes,
                    "rent_12m": rent_12m,
                })
            rf_nome_buf = None
            continue

        # Linha de nome do ativo (sem R$): buffer para próxima linha de dados
        if "R$" not in l:
            # Ignora cabeçalhos de tabela e ruídos
            if (not re.search(r"PRECIFICA|M.S\s+ATUAL|ANO\s+24|SALDO|QTD|%ALLOC|Estrat.gia\s+Saldo", l, re.I) and
                    not re.match(r"^[\d\s\.\-\%\*\+]+$", l) and
                    not RF_RUIDO_PAT.match(l) and
                    len(l) > 5):
                rf_nome_buf = l

    # ── Parser unificado da POSIÇÃO DETALHADA (retorno por ativo, p/ deságio) ─────
    # Fonte única e correta de rent_ano/rent_mes por ativo; sobrepõe os loops antigos
    # (que confundiam rentabilidade com %CDI). Fallback: mantém o resultado antigo.
    try:
        _pos = _parse_posicao_detalhada(texto)
    except Exception:
        _pos = []
    if _pos:
        acoes     = [{"ticker": a["ticker"] or a["nome"][:8], "nome": a["nome"], "saldo": a["saldo"],
                      "qtd": a["qtd"], "perc": a["perc"], "rent_mes": a["rent_mes"],
                      "rent_ano": a["rent_ano"], "rent_24m": a["rent_24m"]}
                     for a in _pos if a["classe"] == "acoes"]
        fiis_list = [{"ticker": a["ticker"] or a["nome"][:8], "nome": a["nome"], "saldo": a["saldo"],
                      "qtd": a["qtd"], "perc": a["perc"], "rent_mes": a["rent_mes"],
                      "rent_ano": a["rent_ano"], "rent_24m": a["rent_24m"]}
                     for a in _pos if a["classe"] == "fiis"]
        rf_ativos = [{"nome": a["nome"], "classe": a["classe"], "saldo": a["saldo"],
                      "perc": a["perc"], "rent_mes": a["rent_mes"], "rent_ano": a["rent_ano"],
                      "rent_24m": a["rent_24m"], "rent_12m": None}
                     for a in _pos if a["classe"] not in ("acoes", "fiis")]

    return {
        "conta":     conta,
        "assessor":  assessor,
        "data_ref":  data_ref,
        "patrimonio": patrimonio,
        "comp":      comp,
        "caixa":     caixa_perc,
        "rent":      rent,
        "acoes":     acoes,
        "fiis":      fiis_list,
        "rf_ativos": rf_ativos,
        "ret_classe": _parse_ret_classe(texto),
        "texto_completo": texto[:1500],
    }


def extrair_texto_pdf(pdf_bytes):
    import pdfplumber
    texto = ""
    with pdfplumber.open(io.BytesIO(pdf_bytes)) as pdf:
        for p in pdf.pages:
            texto += (p.extract_text() or "") + "\n"
    return texto


# ── Parser da Posição Consolidada (complementa o XPerformance) ────────────────
# O XPerformance mede performance da carteira INVESTIDA; a Posição Consolidada
# mostra o patrimônio REAL (com o caixa em conta), vencimentos, risco e emissores.
_POS_TIPOS_RF = r'LCI|LCA|LC|LF|LFSN|LIG|CDB|RDB|CRA|CRI|CDCA|CCB|DEB|COE'

def _pos_brl(s):
    m = re.search(r'R\$\s*([\d.]+,\d{2})', s or "")
    return float(m.group(1).replace(".", "").replace(",", ".")) if m else None

def parse_posicao_consolidada(pdf_bytes):
    """Foto patrimonial a partir da Posição Consolidada (XP): patrimônio real,
    caixa parado em conta, vencimentos, risco/suitability e emissores (FGC)."""
    try:
        texto = extrair_texto_pdf(pdf_bytes)
    except Exception:
        return {"fonte": "posicao_consolidada", "erro": "falha ao ler o PDF"}
    return _parse_posicao_consolidada_texto(texto)

def _parse_posicao_consolidada_texto(texto):
    L = [l.rstrip() for l in (texto or "").split("\n")]
    o = {"fonte": "posicao_consolidada"}
    # Identificação
    for l in L:
        m = re.search(r'Cliente:\s*(.+?)\s+Conta:\s*(\d+)\s+Perfil:\s*([A-Za-zÀ-ÿ]+)\s+Assessoria:\s*(.+)', l)
        if m:
            o["nome"] = m.group(1).strip(); o["conta"] = m.group(2)
            o["perfil"] = m.group(3).strip().lower()
            o["assessor"] = re.sub(r'\(.*?\)', '', m.group(4)).strip()
            break
    m = re.search(r'Data de refer[êe]ncia:\s*(\d{2}/\d{2}/\d{4})', texto or "")
    o["data_ref"] = m.group(1) if m else ""
    # Patrimônio total / investido / caixa em conta (linha-cabeçalho + próxima)
    for i, l in enumerate(L):
        if re.search(r'PATRIM[ÔO]NIO\s+INVESTIMENTO\s+SALDO DISPON', l) and i + 1 < len(L):
            v = re.findall(r'R\$\s*[\d.]+,\d{2}', L[i + 1])
            if len(v) >= 3:
                o["patrimonio_total"] = _pos_brl(v[0]); o["investido"] = _pos_brl(v[1]); o["saldo_conta"] = _pos_brl(v[2])
            break
    if not o.get("patrimonio_total"):
        m = re.search(r'PATRIM[ÔO]NIO TOTAL\s+(R\$\s*[\d.]+,\d{2})', texto or "")
        o["patrimonio_total"] = _pos_brl(m.group(1)) if m else None
    if o.get("saldo_conta") is None:
        m = re.search(r'SALDO DISPON[ÍI]VEL\s+(R\$\s*[\d.]+,\d{2})', texto or "")
        o["saldo_conta"] = _pos_brl(m.group(1)) if m else None
    # Próximos vencimentos (fonte mais limpa por ativo)
    venc = []
    for l in L:
        m = re.match(r'^(.+?)\s+(\d{2}/\d{2}/\d{4})\s+(\d{2}/\d{2}/\d{4})\s+(R\$\s*[\d.]+,\d{2})\s+(.+?)\s+(\d+)\s+(R\$\s*[\d.]+,\d{2})$', l)
        if m and re.match(r'^(' + _POS_TIPOS_RF + r')\b', m.group(1)):
            venc.append({"titulo": m.group(1).strip(), "aplicacao": m.group(2), "vencimento": m.group(3),
                         "aplicado": _pos_brl(m.group(4)), "taxa": m.group(5).strip(),
                         "ir": int(m.group(6)), "liquido": _pos_brl(m.group(7))})
    o["vencimentos"] = venc
    # RF por ativo (nome + linha de dados): tipo, emissor, classe, vencimento, valor.
    # A linha de dados tem 3 datas + taxa? + 3 inteiros + 4 valores R$ (último = líquido).
    _DATAROW = re.compile(r'(\d{2}/\d{2}/\d{4})\s+(\d{2}/\d{2}/\d{4})\s+(\d{2}/\d{2}/\d{4})\s+'
                          r'(.*?)(\d+)\s+(\d+)\s+(\d+)\s+(R\$\s*[\d.]+,\d{2})\s+(R\$\s*[\d.]+,\d{2})'
                          r'\s+(R\$\s*[\d.]+,\d{2})\s+(R\$\s*[\d.]+,\d{2})\s*$')
    def _norm_emis(n):
        n = re.sub(r'\s+', ' ', n or '').strip().upper()
        n = re.sub(r'\s*(S\.?/?A\.?|LTDA)\.?$', '', n).strip()
        n = re.sub(r'^BANCO\s+', '', n).strip()
        return n
    rf_ativos = []; classe_atual = None
    for i, l in enumerate(L):
        mc = re.search(r'([\d.,]+)%\s*\|\s*(Prefixada|Pós-Fixada|Pos-Fixada|Inflação|Inflacao)', l)
        if mc: classe_atual = mc.group(2)
        m = _DATAROW.search(l)
        if not m:
            continue
        prefix = l[:m.start()].strip()
        nome_ativo = prefix if re.match(r'^(' + _POS_TIPOS_RF + r'|NTN|LTN|LFT)\b', prefix) else (L[i-1].strip() if i > 0 else "")
        tm = re.match(r'^(' + _POS_TIPOS_RF + r')\s+(.+?)\s+-(?:\s|$)', nome_ativo)
        rf_ativos.append({"tipo": tm.group(1) if tm else None,
                          "emissor": _norm_emis(tm.group(2)) if tm else None,
                          "classe": classe_atual, "vencimento": m.group(3),
                          "valor": _pos_brl(m.group(11))})
    o["rf_ativos"] = rf_ativos
    # FGC por emissor: só emissões bancárias cobertas (CDB/RDB/LCI/LCA/LC/LIG/LFSN/LF).
    # CRA, CRI, CDCA, DEB, COE e Tesouro (NTN/LTN/LFT) NÃO têm FGC.
    _FGC_TIPOS = {"CDB", "RDB", "LCI", "LCA", "LC", "LIG", "LFSN", "LF"}
    fgc = {}
    for a in rf_ativos:
        if a["tipo"] in _FGC_TIPOS and a["emissor"] and a["valor"]:
            fgc[a["emissor"]] = fgc.get(a["emissor"], 0.0) + a["valor"]
    o["emissores_fgc"] = [{"emissor": k, "valor": round(v, 2), "acima_teto": v > 250000}
                          for k, v in sorted(fgc.items(), key=lambda x: -x[1])]
    # Fundos de investimento (formato: nome + 1 data + cotas + valor + 3x R$; líquido = último)
    _FUNDROW = re.compile(r'^(.+?)\s+(\d{2}/\d{2}/\d{4})\s+([\d.]+)\s+([\d.,]+)\s+'
                          r'R\$\s*[\d.,]+\s+R\$\s*[\d.,]+\s+R\$\s*([\d.]+,\d{2})\s*$')
    def _classe_fundo(sec):
        n = (sec or "").lower()
        if "multimerc" in n: return "Multimercado"
        if "renda variável" in n or "renda variavel" in n or "ações" in n or "acoes" in n: return "Renda Variável"
        if "global" in n or "exterior" in n or "cambial" in n or "internacional" in n: return "Internacional"
        if "imobili" in n: return "Fundos Imobiliários"
        if "renda fixa" in n or "crédito" in n or "credito" in n: return "Fundos RF"
        if "previd" in n: return "Previdência"
        return "Outros fundos"
    fundos = []; _sec_fundo = None
    for l in L:
        ms = re.match(r'^\s*[\d.,]+%?\s*\|?\s*((?:Fundos|Ações|Acoes|Previd)[^\n]*?)\s*$', l)
        if ms and len(ms.group(1)) < 60:
            _sec_fundo = ms.group(1).strip()
        mf = _FUNDROW.match(l.strip())
        if mf:
            nome_f = mf.group(1).strip()
            if re.match(r'^(' + _POS_TIPOS_RF + r'|NTN|LTN|LFT)\b', nome_f):
                continue
            fundos.append({"nome": nome_f, "classe": _classe_fundo(_sec_fundo), "valor": _pos_brl("R$ " + mf.group(5))})
    o["fundos"] = fundos
    # Composição por classe (R$ e %): caixa + RF (títulos) + fundos + resto (COE/prev.)
    pt2 = o.get("patrimonio_total") or 0
    comp = {}
    if o.get("saldo_conta"): comp["Caixa"] = o["saldo_conta"]
    _rf_sum = sum(a["valor"] or 0 for a in rf_ativos)
    if _rf_sum: comp["Renda Fixa"] = _rf_sum
    for fu in fundos:
        comp[fu["classe"]] = comp.get(fu["classe"], 0) + (fu["valor"] or 0)
    if pt2:
        _resto = pt2 - sum(comp.values())
        if _resto > pt2 * 0.01:
            comp["Outros (COE/prev.)"] = round(_resto, 2)
    o["composicao"] = [{"classe": k, "valor": round(v, 2), "pct": round(100 * v / pt2, 1) if pt2 else 0}
                       for k, v in sorted(comp.items(), key=lambda x: -x[1])]
    # Confiável quando o "resto" (tipos não parseados, ex.: Tesouro/COE em carteiras
    # de crédito complexas) é pequeno. Senão a composição é parcial e não deve ser exibida.
    _outros = next((c["pct"] for c in o["composicao"] if c["classe"].startswith("Outros (COE")), 0)
    o["composicao_confiavel"] = bool(pt2) and _outros < 20
    # Risco / suitability (N Pts (Limite: X)) — status numérico confiável
    m = re.search(r'(\d+)\s*Pts\s*\(Limite:\s*(\d+)\)', texto or "")
    if m:
        o["risco_atual"] = int(m.group(1)); o["risco_limite"] = int(m.group(2))
        uso = o["risco_atual"] / o["risco_limite"] if o["risco_limite"] else 0
        o["risco_uso"] = round(uso, 2)
        o["risco_status"] = "acima_do_limite" if uso > 1.0 else ("subalocado" if uso < 0.6 else "ok")
    # Resumo computado: caixa % do patrimônio + ladder de vencimentos
    def _dt(s):
        try: return datetime.strptime(s, "%d/%m/%Y").date()
        except Exception: return None
    ref = _dt(o.get("data_ref") or "") or agora_br().date()
    d30 = d60 = d90 = 0.0
    for v in venc:
        dv = _dt(v["vencimento"])
        if not dv: continue
        dd = (dv - ref).days
        if 0 <= dd <= 30: d30 += v["liquido"] or 0
        if 0 <= dd <= 60: d60 += v["liquido"] or 0
        if 0 <= dd <= 90: d90 += v["liquido"] or 0
    cx = o.get("saldo_conta") or 0; pt = o.get("patrimonio_total") or 0
    o["resumo"] = {"caixa_pct": round(100 * cx / pt, 1) if pt else 0,
                   "venc_30d": round(d30, 2), "venc_60d": round(d60, 2), "venc_90d": round(d90, 2),
                   "oportunidade_90d": round(cx + d90, 2)}
    return o


def calcular_desvios(comp, modelo):
    resultado = []
    for cat in CATS:
        real, alvo = comp.get(cat, 0.0), modelo.get(cat, 0.0)
        resultado.append({"cat":cat,"label":LABELS[cat],"real":round(real,2),"alvo":round(alvo,2),"desvio":round(real-alvo,2)})
    return sorted(resultado, key=lambda x: abs(x["desvio"]), reverse=True)


def avaliar_modelo_servir(checklist_input):
    """Avalia cada pilar do Modelo de Servir com base no input do assessor."""
    resultado = []
    pendentes_criticos = 0
    pendentes_altos = 0

    for pilar in MODELO_SERVIR:
        feito = checklist_input.get(pilar["id"], False)
        status = "ok" if feito else "pendente"
        if not feito:
            if pilar["importancia"].startswith("CRÍTICA"):
                pendentes_criticos += 1
            elif pilar["importancia"].startswith("ALTA"):
                pendentes_altos += 1
        resultado.append({
            "id": pilar["id"],
            "nome": pilar["nome"],
            "icone": pilar["icone"],
            "descricao": pilar["descricao"],
            "importancia": pilar["importancia"],
            "impacto_falta": pilar["impacto_falta"],
            "acao": pilar["acao"],
            "status": status,
            "diretriz": pilar.get("diretriz", False),
            "cor": pilar["cor"],
        })

    score = sum(1 for r in resultado if r["status"] == "ok")
    return resultado, score, pendentes_criticos, pendentes_altos


def avaliar_cross_sell(cross_input):
    """Avalia quais áreas de cross sell o cliente já tem e quais estão em aberto."""
    resultado = []
    tem = []
    nao_tem = []
    for area in CROSS_SELL:
        ativo = cross_input.get(area["id"], False)
        item = {
            "id": area["id"],
            "nome": area["nome"],
            "icone": area["icone"],
            "descricao": area["descricao"],
            "pitch": area["pitch"],
            "oportunidades": area.get("oportunidades", []),
            "especialista": area.get("especialista"),
            "ativo": ativo,
        }
        resultado.append(item)
        if ativo:
            tem.append(area["nome"])
        else:
            nao_tem.append(area["nome"])
    return resultado, tem, nao_tem


def _carregar_compliance():
    """Carrega texto dos documentos de compliance publicados na base de conhecimento."""
    try:
        docs = [d for d in load_know_index() if d.get("publicado") and d.get("tipo") in ("compliance", "outro")]
        textos = []
        for doc in docs:
            t = load_know_text(doc["id"])
            if t:
                textos.append(f"[{doc.get('nome','')}]\n{t[:4000]}")
        return "\n\n---\n\n".join(textos)
    except Exception:
        return ""

# Regras extraídas do compliance XP, usadas como guardrail hard-coded para análise offline
_COMPLIANCE_RULES = [
    # Concentração máxima por ativo/emissor
    {"regra": "max_ativo_pct", "valor": 20,
     "msg": "Compliance XP: concentração máxima de 20% em um único emissor de renda fixa."},
    {"regra": "max_rv_pct", "valor": 30,
     "msg": "Compliance XP: exposição máxima de 30% em Renda Variável para perfil não-agressivo."},
    # Diversificação mínima
    {"regra": "min_classes", "valor": 3,
     "msg": "Compliance XP: carteira deve ter no mínimo 3 classes de ativos."},
    # Produtos estruturados / alternativos
    {"regra": "alt_max_pct", "valor": 15,
     "msg": "Compliance XP: Alternativos e Estruturados limitados a 15% do patrimônio total."},
    # Liquidez mínima
    {"regra": "liquidez_min_pct", "valor": 10,
     "msg": "Compliance XP: mínimo de 10% em ativos de liquidez diária (Pós Fixado / Caixa)."},
]

def aplicar_compliance(recomendacoes, alertas, comp, perfil):
    """Valida recomendações contra as regras de compliance e adiciona alertas de violação."""
    compliance_alertas = []

    # Regra: concentração por classe
    for cat, pct in comp.items():
        if cat == "alternativos" and pct > 15:
            compliance_alertas.append(
                f"⚠️ Alerta de suitability: Alternativos em {pct:.1f}%, para o perfil {perfil.title()}, a exposição a ativos ilíquidos merece reavaliação (liquidez e prazo de resgate).")
        if cat == "acoes" and perfil not in ("arrojada", "agressiva") and pct > 30:
            compliance_alertas.append(
                f"⚠️ Alerta de suitability: a exposição em Renda Variável ({pct:.1f}%) é elevada para o perfil {perfil.title()} informado e merece reavaliação.")

    # Regra: diversificação mínima
    classes_com_posicao = sum(1 for v in comp.values() if v >= 1.0)
    if classes_com_posicao < 3:
        compliance_alertas.append(
            "⚠️ Diversificação: a carteira concentra-se em menos de 3 classes de ativos, a diversificação pode ser ampliada.")

    # Regra: liquidez mínima (pós fixado + caixa)
    liquidez = comp.get("pos_fixado", 0)
    if liquidez < 10:
        compliance_alertas.append(
            f"⚠️ Liquidez: parcela pós-fixada em {liquidez:.1f}%, avaliar a reserva efetivamente disponível em D+0/D+1 (nem todo pós-fixado tem liquidez diária).")

    # Injeta alertas de compliance NO INÍCIO da lista de alertas
    alertas = compliance_alertas + alertas

    # Filtra recomendações que violem compliance
    recomendacoes_validas = []
    for rec in recomendacoes:
        # Bloqueia sugestão de aumentar alternativos se já está no limite
        if rec.get("classe","").lower() in ("alternativos","estruturados") and comp.get("alternativos",0) >= 15:
            rec["bloqueado_compliance"] = True
            rec["compliance_nota"] = "Limite XP de 15% em Alternativos atingido, sugestão bloqueada pelo compliance."
        # Bloqueia sugestão de RV para perfil conservador/super_conservador
        if rec.get("classe","").lower() in ("ações / rv","ações","acoes") and perfil in ("conservadora","super_conservadora"):
            rec["bloqueado_compliance"] = True
            rec["compliance_nota"] = "Perfil conservador: XP não permite recomendação ativa de aumento em Renda Variável."
        recomendacoes_validas.append(rec)

    return recomendacoes_validas, alertas

def gerar_recomendacoes(desvios, perfil, macro, contexto, carta_texto="", comp=None):
    selic = macro.get("selic_meta")
    ipca  = macro.get("ipca_12m")
    rec_classes = contexto.get("recomendacoes_por_classe", {})
    visao = contexto.get("visao_gestores", [])

    frags = [d for d in desvios if d["desvio"] < -1.5]
    opors = [d for d in desvios if d["desvio"] > 1.5]
    recomendacoes = []

    gestores_resumo = "; ".join([f"{v['gestor']}: {v['implicacao_alocacao']}" for v in visao[:3]])

    carta_insights = []
    if carta_texto:
        for cat in CATS:
            label = LABELS[cat]
            for linha in carta_texto.splitlines():
                if any(p in linha.lower() for p in [cat.replace("_"," "), label.lower(), "ipca","selic","inflação","pós-fixado","prefixado"]):
                    trecho = linha.strip()
                    if len(trecho) > 30:
                        carta_insights.append({"classe": label, "trecho": trecho[:200]})
                        break

    for f in frags:
        cat = f["cat"]
        rc  = rec_classes.get(cat, {})
        produtos = rc.get("produtos_sugeridos", [])
        ctx_gestor = rc.get("contexto_gestor", "")

        # Urgência pelo TAMANHO DO GAP (falta): <5pp = baixa · 5–10pp = média · >10pp = urgente
        _gap = abs(f.get("desvio", 0))
        if _gap > 10:
            urgencia = "Prioridade alta"
        elif _gap >= 5:
            urgencia = "Prioridade moderada"
        else:
            urgencia = "Prioridade complementar"

        if cat == "inflacao":
            macro_txt = f"IPCA 12M em {ipca:.1f}%" if ipca else "IPCA elevado"
            explicacao = f"{macro_txt}, cliente sem proteção inflacionária ({f['real']:.1f}% vs. alvo {f['alvo']:.1f}%). {ctx_gestor}"
        elif cat == "pre_fixado":
            macro_txt = f"Selic em {selic:.2f}%" if selic else "Selic elevada"
            explicacao = f"{macro_txt} próxima do pico. Pré-fixado de médio prazo pode capturar ganho de capital com início de ciclo de queda. {ctx_gestor}"
        elif cat == "internacional":
            explicacao = f"Diversificação cambial ausente ({f['real']:.1f}% vs. alvo {f['alvo']:.1f}%). SPX e Ibiuna destacam internacional como hedge. {ctx_gestor}"
        elif cat == "multimercado":
            explicacao = f"Ausência de diversificador macro. {ctx_gestor}"
        elif cat == "acoes":
            explicacao = f"Renda variável abaixo do modelo. Cautela: Verde e Absolute neutros/negativos para bolsa Brasil. {ctx_gestor}"
        else:
            explicacao = f"{f['label']} abaixo do modelo em {abs(f['desvio']):.1f}%. {ctx_gestor}"

        carta_insight = next((c["trecho"] for c in carta_insights if f['label'].lower() in c["classe"].lower()), "")

        recomendacoes.append({
            "classe": f["label"],
            "urgencia": urgencia,
            "falta_pp": abs(f["desvio"]),
            "explicacao": explicacao,
            "produtos": produtos[:4],
            "carta_insight": carta_insight,
            "consenso_gestores": gestores_resumo,
        })

    alertas = []
    for o in opors:
        cat = o["cat"]
        if cat == "alternativos" and o["desvio"] > 5:
            alertas.append(f"⚠️ {o['label']} com {o['real']:.1f}% vs. alvo {o['alvo']:.1f}%, Absolute alerta: fundos alternativos ilíquidos (FIPs) inadequados para perfil {perfil}. Verificar liquidez e prazo de resgate.")
        elif cat == "pos_fixado" and o["desvio"] > 5:
            alertas.append(f"⚠️ {o['label']} com {o['real']:.1f}% vs. alvo {o['alvo']:.1f}%, XP Asset e Verde alertam para concentração excessiva em pós-fixado. Realocar gradualmente para inflação.")
        else:
            alertas.append(f"⚠️ {o['label']} com excesso de {o['desvio']:.1f}%, candidato à realocação.")

    # Aplica guardrails de compliance antes de retornar
    if comp:
        recomendacoes, alertas = aplicar_compliance(recomendacoes, alertas, comp, perfil)

    # Ordena por maior gap primeiro (urgente no topo)
    recomendacoes.sort(key=lambda r: -float(r.get("falta_pp", 0) or 0))
    return recomendacoes, alertas


def _fmt_brl(v):
    try:
        return f"R$ {float(v):,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")
    except Exception:
        return "R$ 0,00"

def _classe_slug(label):
    import unicodedata
    s = unicodedata.normalize("NFKD", str(label or "")).encode("ascii", "ignore").decode().lower()
    if "acao" in s or "acoes" in s or s.strip() in ("rv",): return "acoes"
    if "inflac" in s: return "inflacao"
    if "pos" in s and "fix" in s: return "pos_fixado"
    if "pre" in s and "fix" in s: return "pre_fixado"
    if "internac" in s: return "internacional"
    if "fii" in s: return "fiis"
    if "multi" in s: return "multimercado"
    if "alternativ" in s: return "alternativos"
    if "cripto" in s: return "cripto"
    return s

