def _olhar_mercado_blocos(desvios, caixa, macro, modelo_lbl, perfil_lbl):
    """Retorna blocos (tipo, texto) para o 'Olhar de Mercado', análise completa da
    alocação do cliente + conhecimento por classe + cenário macro/eleitoral 2026."""
    if not desvios:
        return []
    ordenados = sorted(desvios, key=lambda d: d.get("desvio", 0), reverse=True)
    maior = ordenados[0]
    gaps = [d for d in ordenados if d.get("desvio", 0) <= -3]
    gaps = sorted(gaps, key=lambda d: d.get("desvio", 0))[:4]
    selic = f"{macro.get('selic_meta'):.2f}%" if macro and macro.get('selic_meta') else "patamar elevado"
    ipca  = f"{macro.get('ipca_12m'):.2f}%" if macro and macro.get('ipca_12m') else "a inflação corrente"
    blocos = []

    # 1) Diagnóstico geral
    blocos.append(("sub", "Diagnóstico da alocação atual"))
    if maior.get("desvio", 0) > 5:
        blocos.append(("p",
            f"A carteira está desenhada de forma desbalanceada em relação ao modelo {modelo_lbl} para o perfil {perfil_lbl}. "
            f"A maior concentração está em <b>{maior['label']}</b>, que responde por {maior['real']:.1f}% do patrimônio contra "
            f"{maior['alvo']:.1f}% do modelo, um excesso de {maior['desvio']:.1f} pontos percentuais. Concentrar tanto risco em "
            f"um único indexador significa que o resultado da carteira passa a depender quase inteiramente do comportamento de um "
            f"único fator, reduzindo a diversificação e ampliando a oscilação em momentos de estresse."))
    else:
        blocos.append(("p",
            f"A carteira está relativamente próxima do modelo {modelo_lbl} para o perfil {perfil_lbl}, sem uma concentração dominante. "
            f"Ainda assim, há ajustes de alocação que melhoram a relação risco/retorno, detalhados a seguir."))

    # 2) Leitura da classe concentrada
    ins_maior = _CLASSE_INSIGHT.get(_classe_slug(maior['label']))
    if maior.get("desvio", 0) > 5 and ins_maior:
        blocos.append(("sub", f"Concentração em {maior['label']}"))
        blocos.append(("p", ins_maior["conc"]))

    # 3) Classes ausentes / sub-alocadas
    if gaps:
        blocos.append(("sub", "Classes ausentes ou sub-alocadas"))
        for g in gaps:
            ins = _CLASSE_INSIGHT.get(_classe_slug(g['label']))
            papel = ins["papel"] if ins else "diversificação da carteira"
            blocos.append(("p",
                f"<b>{g['label']}</b> ({g['real']:.1f}% vs. {g['alvo']:.1f}% do modelo): {papel}. "
                f"A sub-alocação nessa classe reduz a diversificação e a capacidade de reposicionamento da carteira."))

    # 4) Cenário macro e eleições 2026
    blocos.append(("sub", "Cenário 2026, ano eleitoral, juros e câmbio"))
    _macro_txt = (f"Com a Selic meta em {selic} e o IPCA acumulando {ipca} em 12 meses, "
                  if (macro and macro.get('selic_meta') and macro.get('ipca_12m')) else "")
    blocos.append(("p",
        f"O processo eleitoral de 2026 pode aumentar a volatilidade dos ativos locais e do câmbio ao longo do ano, à medida que o "
        f"mercado antecipa a incerteza fiscal. {_macro_txt}a diversificação por indexador tende a ajudar: pós-fixado para liquidez, "
        f"inflação (IPCA+) para proteção do poder de compra, pré-fixado para capturar um eventual início de ciclo de queda de juros e "
        f"internacional para reduzir a dependência exclusiva do mercado brasileiro. Carteiras concentradas em um único fator de risco "
        f"tendem a ser mais sensíveis a oscilações de cenário."))
    blocos.append(("p",
        "Na renda fixa, o juro real elevado costuma ser uma janela atrativa para posições em IPCA+, considerando a marcação a mercado "
        "no caminho. Na renda variável, o valuation descontado da bolsa local convive com o risco eleitoral, o que reforça a importância "
        "de horizonte, gestão de risco e proteção perto dos alvos. A diversificação internacional pode contribuir para reduzir a "
        "dependência exclusiva do mercado brasileiro e a exposição ao real."))

    # 5) Fragilidades
    frags = []
    if maior.get("desvio", 0) > 5:
        frags.append(f"Concentração de {maior['real']:.1f}% em {maior['label']}, risco dependente de um único fator.")
    if any(_classe_slug(g['label']) == "internacional" for g in gaps):
        frags.append("Sem hedge cambial (internacional sub-alocado), patrimônio 100% exposto ao risco-Brasil.")
    if all(_classe_slug(g['label']) != "acoes" for g in gaps) and maior.get("desvio",0)<=5:
        pass
    divers = [g for g in gaps if _classe_slug(g['label']) in ("multimercado", "fiis", "alternativos")]
    if divers:
        frags.append("Ausência de diversificadores (multimercado/FIIs), menor descorrelação em cenários adversos.")
    if caixa and caixa >= 5:
        frags.append(f"{caixa:.1f}% em caixa fora do modelo, capital ocioso a ser realocado.")
    if not frags:
        frags.append("Ajustes pontuais de alocação para alinhar a carteira ao modelo e ao perfil.")
    blocos.append(("sub", "Principais fragilidades"))
    for f in frags:
        blocos.append(("frag", "• " + f))

    return blocos

def _texto_racional_modelo(modelo_lbl, perfil_lbl):
    """Racional das recomendações: explora o modelo escolhido e seus benefícios."""
    return (
        f"As recomendações a seguir seguem o modelo <b>{modelo_lbl}</b>, selecionado para o perfil {perfil_lbl}. "
        f"Esse modelo distribui a carteira por indexador, pós-fixado, inflação (IPCA+), pré-fixado, internacional e "
        f"diversificadores, buscando equilibrar proteção e retorno ao longo do ciclo econômico. O objetivo é aproximar "
        f"a carteira atual desse modelo: corrigir as concentrações, preencher as lacunas e, com isso, melhorar a relação "
        f"risco/retorno e a resiliência a diferentes cenários de mercado."
    )

def _plano_troca_resumo(plano):
    """Agrega o plano_troca (venda→compra) em listas, MESMA fonte para o PDF (assessor)
    e o Braúna 360° (cliente), garantindo números idênticos. Retorna dict ou None."""
    if not plano or not isinstance(plano, dict):
        return None
    movs = plano.get("movimentacoes") or []
    if not movs and not (plano.get("bloqueados") or plano.get("previdencia")):
        return None
    red, comp = {}, {}
    for m in movs:
        ok = (m.get("origem_nome") or "n/d", m.get("origem_label") or "")
        r = red.setdefault(ok, {"nome": ok[0], "label": ok[1], "valor": 0.0, "desagio": m.get("origem_desagio")})
        r["valor"] += m.get("valor") or 0
        ck = (m.get("destino_produto") or "n/d", m.get("destino_label") or "")
        c = comp.setdefault(ck, {"nome": ck[0], "label": ck[1], "valor": 0.0, "detalhe": m.get("destino_detalhe") or ""})
        c["valor"] += m.get("valor") or 0
    return {
        "total":   plano.get("total_mover") or sum(m.get("valor") or 0 for m in movs),
        "reduzir": sorted(red.values(),  key=lambda x: -x["valor"]),
        "comprar": sorted(comp.values(), key=lambda x: -x["valor"]),
        "bloqueados":  plano.get("bloqueados") or [],
        "previdencia": plano.get("previdencia") or [],
        "limite_desagio": plano.get("limite_desagio", 3),
    }


def gerar_pdf(nome, perfil, desvios, rent, patrimonio, caixa, data_ref, recomendacoes, alertas, macro, ref_contexto, checklist_servir=None, acoes=None, conta="", assessor="", modelo_nome="", plano_troca=None):
    # Normaliza os desvios: analyze-xp usa 'atual'/'cls'; o PDF espera 'real'/'cat'.
    desvios = [{**d, "real": d.get("real", d.get("atual", 0)), "cat": d.get("cat", d.get("cls"))}
               for d in (desvios or [])]
    from reportlab.lib.pagesizes import A4
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, HRFlowable, Image, Flowable, PageBreak
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER
    import matplotlib; matplotlib.use("Agg")
    import matplotlib.pyplot as plt
    import numpy as np

    PRETO=colors.HexColor("#17271E"); DOURADO=colors.HexColor("#8A6A28"); DESC=colors.HexColor("#A07840")
    CESC=colors.HexColor("#FFFFFF"); CMED=colors.HexColor("#F4F6F4"); BRANCO=colors.HexColor("#17271E")
    VERM=colors.HexColor("#C0392B"); VERDE=colors.HexColor("#2E7D5B"); AMARELO=colors.HexColor("#B4833A")
    LARANJA=colors.HexColor("#C0673A")

    buf=io.BytesIO()
    doc=SimpleDocTemplate(buf,pagesize=A4,leftMargin=2*cm,rightMargin=2*cm,topMargin=2*cm,bottomMargin=2*cm)
    ss=getSampleStyleSheet()
    def S(n,**kw): return ParagraphStyle(n,parent=ss["Normal"],textColor=kw.pop("tc",BRANCO),**kw)

    s_title=S("T",fontSize=18,leading=22,tc=DOURADO,alignment=TA_CENTER,spaceAfter=4)
    s_sub=S("S",fontSize=10,tc=DESC,alignment=TA_CENTER,spaceAfter=2)
    s_sec=S("Se",fontSize=11,tc=DOURADO,spaceBefore=10,spaceAfter=4)
    s_body=S("B",fontSize=9,leading=13)
    s_rod=S("R",fontSize=7,tc=colors.HexColor("#4A7055"),alignment=TA_CENTER)
    s_frag=S("F",fontSize=9,leading=13,tc=VERM)
    s_opor=S("O",fontSize=9,leading=13,tc=VERDE)
    s_sug=S("Su",fontSize=9,leading=14,tc=DOURADO)
    s_bold=S("Sb",fontSize=9,leading=13,tc=BRANCO,fontName="Helvetica-Bold")
    s_gest=S("Sg",fontSize=8,leading=12,tc=colors.HexColor("#5A6A60"))
    s_crit=S("Sc",fontSize=9,leading=13,tc=VERM,fontName="Helvetica-Bold")
    s_warn=S("Sw",fontSize=9,leading=13,tc=AMARELO)
    s_ok=S("Sok",fontSize=9,leading=13,tc=VERDE)
    s_olh_h=S("Oh",fontSize=9.5,leading=12,tc=DOURADO,fontName="Helvetica-Bold",spaceBefore=7,spaceAfter=2)
    s_olh_b=S("Ob",fontSize=9,leading=14,tc=colors.HexColor("#2C2C2C"),spaceAfter=3)
    s_frag2=S("Fr",fontSize=9,leading=13,tc=AMARELO)

    modelo_lbl = (modelo_nome or "").strip() or "Levante Asset"

    elems=[]
    elems.append(Paragraph("BRAÚNA INVESTIMENTOS",s_title))
    elems.append(Paragraph(f"Análise de Alocação por Indexador, Modelo {modelo_lbl}",s_sub))
    elems.append(HRFlowable(width="100%",thickness=1,color=DOURADO,spaceAfter=8))

    perfil_pt={"super_conservadora":"Super Conservadora","conservadora":"Conservadora","moderada":"Moderada","arrojada":"Arrojada","agressiva":"Agressiva"}
    perfil_lbl = perfil_pt.get(perfil, perfil)
    pat_fmt=f"R$ {patrimonio:,.2f}".replace(",","X").replace(".",",").replace("X",".")
    _conta = str(conta or "").strip()
    _nome  = str(nome or "").strip()
    cliente_txt = (f"{_conta}, {_nome}" if (_conta and _nome) else (_conta or _nome or "n/d"))
    assessor_txt = str(assessor or "").strip() or "n/d"
    meta=[
        ["Cliente:",cliente_txt,"Assessor:",assessor_txt],
        ["Perfil:",perfil_lbl,"Data ref.:",data_ref],
        ["Patrimônio:",pat_fmt,"Caixa:",f"{caixa:.1f}% (excluído do modelo)"],
    ]
    # Só mostra a linha macro quando houver dado real (nunca "n/d")
    if macro.get('selic_meta') and macro.get('ipca_12m'):
        meta.append(["Selic meta:",f"{macro['selic_meta']:.2f}%","IPCA 12M:",f"{macro['ipca_12m']:.2f}%"])
    tm=Table(meta,colWidths=[2.6*cm,7*cm,2.6*cm,5*cm])
    tm.setStyle(TableStyle([
        ("FONTSIZE",(0,0),(-1,-1),8),("TEXTCOLOR",(0,0),(-1,-1),BRANCO),
        ("TEXTCOLOR",(0,0),(0,-1),DOURADO),("TEXTCOLOR",(2,0),(2,-1),DOURADO),
        ("ROWBACKGROUNDS",(0,0),(-1,-1),[CESC,CMED]),
        ("GRID",(0,0),(-1,-1),0.3,colors.HexColor("#D9E3DB")),("PADDING",(0,0),(-1,-1),4),
    ]))
    elems.append(tm); elems.append(Spacer(1,0.3*cm))

    # Olhar de mercado sobre a carteira atual e suas fragilidades (antes do checklist)
    _blocos = _olhar_mercado_blocos(desvios, caixa, macro, modelo_lbl, perfil_lbl)
    if _blocos:
        elems.append(HRFlowable(width="100%",thickness=0.5,color=DESC,spaceAfter=4))
        elems.append(Paragraph("Olhar de Mercado, Carteira Atual e Fragilidades",s_sec))
        for _tipo,_txt in _blocos:
            if _tipo=="sub":    elems.append(Paragraph(_txt, s_olh_h))
            elif _tipo=="frag": elems.append(Paragraph(_txt, s_frag2))
            else:               elems.append(Paragraph(_txt, s_olh_b))
        elems.append(Spacer(1,0.3*cm))

    # Próximas etapas do planejamento (versão do cliente, sem conteúdo interno do assessor)
    elems.append(HRFlowable(width="100%",thickness=0.5,color=DESC,spaceAfter=4))
    # Foto Patrimonial — da Posição Consolidada salva (se válida, < 3 dias), técnica
    _posp = carregar_posicao(conta) if conta else None
    if _posp and not _posicao_validade(_posp.get("salvo_em")).get("valida"):
        _posp = None   # Posição vencida: não entra no PDF até re-subir
    if _posp and _posp.get("patrimonio_total"):
        _rpp = _posp.get("resumo") or {}
        def _fbrl(v):
            return ("R$ " + f"{(v or 0):,.2f}".replace(",", "X").replace(".", ",").replace("X", "."))
        def _esc(s):
            return str(s or "").replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
        elems.append(Paragraph("Foto Patrimonial, Posição Consolidada"
                               + (f" (ref. {_posp.get('data_ref')})" if _posp.get('data_ref') else ""), s_sec))
        _cxp = _rpp.get("caixa_pct") or 0
        elems.append(Paragraph(
            f"Patrimônio real <b>{_fbrl(_posp.get('patrimonio_total'))}</b>. Investido {_fbrl(_posp.get('investido'))}. "
            f"Caixa em conta <b>{_fbrl(_posp.get('saldo_conta'))}</b> ({_cxp:.0f}% do patrimônio). "
            f"Para realocar (caixa mais vencimentos em 90 dias): <b>{_fbrl(_rpp.get('oportunidade_90d'))}</b>.", s_body))
        if _posp.get("risco_atual") is not None:
            _lbl = {"acima_do_limite": "acima do limite (desenquadrado por excesso)",
                    "subalocado": "subalocado em risco", "ok": "dentro do limite"}.get(_posp.get("risco_status"), "")
            elems.append(Paragraph(f"Risco atual {_posp['risco_atual']} de {_posp.get('risco_limite')}, {_lbl}.", s_body))
        _vs = _posp.get("vencimentos") or []
        if _vs:
            _lv = "; ".join(f"{_esc(v['titulo'])} (venc. {v['vencimento']}, {_fbrl(v['liquido'])})" for v in _vs[:6])
            elems.append(Paragraph(f"<b>Vencimentos:</b> {_lv}.", s_body))
        _fg = _posp.get("emissores_fgc") or []
        if _fg:
            _lf = ", ".join(f"{_esc(e['emissor'])} {_fbrl(e['valor'])}" + (" (ACIMA DO TETO)" if e.get("acima_teto") else "") for e in _fg[:6])
            elems.append(Paragraph(f"<b>FGC por emissor (teto R$ 250 mil/conglomerado):</b> {_lf}.", s_body))
        elems.append(Spacer(1, 0.3 * cm))

    elems.append(Paragraph("Próximas etapas do planejamento",s_sec))
    for _i,_e in enumerate([
        "Consolidar o patrimônio total, inclusive posições fora da XP.",
        "Mapear objetivos, prazos e necessidade de liquidez.",
        "Validar a capacidade de risco e eventuais restrições.",
        "Elaborar a proposta detalhada de transição da carteira.",
        "Executar a realocação de forma gradual e acompanhada.",
    ],1):
        elems.append(Paragraph(f"{_i}. {_e}", s_body))
    elems.append(Spacer(1,0.25*cm))

    if rent.get("portfolio") and rent.get("cdi"):
        p,c=rent["portfolio"],rent["cdi"]
        def _pct(v): return "n/d" if v is None else f'{v:.2f}%'
        def _dpp(a,b): return "n/d" if (a is None or b is None) else f'{a-b:+.2f} p.p.'
        rd=[["Período","Carteira","CDI","Diferença (p.p.)"]]
        for _lb,_k in [("Mês","mes"),("Ano","ano"),("12M","12m"),("24M","24m")]:
            if p.get(_k) is None:   # carteira ainda não tem esse período (ex.: carteira nova)
                continue
            rd.append([_lb,_pct(p.get(_k)),_pct(c.get(_k)),_dpp(p.get(_k),c.get(_k))])
        elems.append(Paragraph("Rentabilidade vs. CDI",s_sec))
        tr=Table(rd,colWidths=[3*cm,4*cm,4*cm,4*cm])
        tr.setStyle(TableStyle([
            ("BACKGROUND",(0,0),(-1,0),DESC),("TEXTCOLOR",(0,0),(-1,0),PRETO),
            ("TEXTCOLOR",(0,1),(-1,-1),BRANCO),("FONTSIZE",(0,0),(-1,-1),8),
            ("ROWBACKGROUNDS",(0,1),(-1,-1),[CESC,CMED]),
            ("GRID",(0,0),(-1,-1),0.3,colors.HexColor("#D9E3DB")),
            ("ALIGN",(1,0),(-1,-1),"CENTER"),("PADDING",(0,0),(-1,-1),4),
            ("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),
        ]))
        elems.append(tr); elems.append(Spacer(1,0.3*cm))

    elems.append(Paragraph(f"Composição Atual vs. Modelo {modelo_lbl}",s_sec))
    # Barras horizontais; remove classes zeradas em ambos (atual e modelo)
    _dv=[d for d in desvios if (d.get("real") or 0)>0 or (d.get("alvo") or 0)>0]
    lbs=[d["label"] for d in _dv]; rea=[d["real"] for d in _dv]; alv=[d["alvo"] for d in _dv]
    y=np.arange(len(lbs)); h=0.38
    fig,ax=plt.subplots(figsize=(10,max(2.4,0.62*len(lbs)+1)))
    fig.patch.set_facecolor("#FFFFFF"); ax.set_facecolor("#FFFFFF")
    b1=ax.barh(y+h/2,rea,h,color="#8A6A28",zorder=3,label="Atual")
    b2=ax.barh(y-h/2,alv,h,color="#2E7D5B",zorder=3,label="Modelo")
    ax.set_yticks(y); ax.set_yticklabels(lbs,color="#17271E",fontsize=9); ax.invert_yaxis()
    ax.tick_params(colors="#17271E"); ax.spines[:].set_color("#D9E3DB")
    ax.xaxis.grid(True,color="#E4E8E7",zorder=0); ax.set_axisbelow(True); ax.set_xlabel("%",color="#17271E")
    _mx=max(rea+alv+[1])
    for bars in (b1,b2):
        for r in bars:
            wv=r.get_width()
            if wv>0: ax.text(wv+_mx*0.01,r.get_y()+r.get_height()/2,f"{wv:.0f}%",va="center",color="#17271E",fontsize=7.5)
    ax.set_xlim(0,_mx*1.13)
    ax.legend(facecolor="#FFFFFF",edgecolor="#D9E3DB",labelcolor="#17271E",fontsize=8,loc="lower right")
    fig.tight_layout(pad=1)
    ib=io.BytesIO(); fig.savefig(ib,format="png",dpi=150,facecolor="#FFFFFF"); plt.close(fig); ib.seek(0)
    _hh=max(3.2,0.72*len(lbs)+1.2)
    elems.append(Image(ib,width=15*cm,height=_hh*cm)); elems.append(Spacer(1,0.3*cm))

    # Rentabilidade, Cliente vs. Carteira Recomendada vs. CDI (linha)
    try:
        _rc = (carregar_retornos() or {}).get("classes", {})
        # Eixo do passado (24M) até o mês atual
        _pers = [("24m","24M"),("12m","12M"),("ano","Ano"),("mes","Mês")]
        _port = (rent.get("portfolio") or {}); _cdi = (rent.get("cdi") or {})
        def _rec_pdf(pk):
            sw = sr = 0.0
            for dd_ in desvios:
                alvo = float(dd_.get("alvo", 0) or 0)
                rr = (_rc.get(dd_.get("cat") or dd_.get("cls")) or {}).get(pk)
                if alvo > 0 and rr is not None:
                    sw += alvo; sr += alvo * float(rr)
            return (sr/sw) if sw > 0 else None
        _cli_vals = [_port.get(pk) for pk,_ in _pers]
        _cdi_vals = [_cdi.get(pk)  for pk,_ in _pers]
        _rec_vals = [_rec_pdf(pk)  for pk,_ in _pers]
        _tem_rec = any(v is not None for v in _rec_vals)
        if any(v is not None for v in _cli_vals):
            _titulo = ("Rentabilidade, Carteira vs. Carteira-Modelo vs. CDI" if _tem_rec
                       else "Rentabilidade da Carteira vs. CDI")
            elems.append(Paragraph(_titulo,s_sec))
            figr,axr=plt.subplots(figsize=(10,3.8))
            figr.patch.set_facecolor("#FFFFFF"); axr.set_facecolor("#FFFFFF")
            _xs=np.arange(len(_pers))
            _series=[(_cli_vals,"#8A6A28","Carteira")]
            if _tem_rec: _series.append((_rec_vals,"#2E7D5B","Carteira-Modelo"))
            _series.append((_cdi_vals,"#2E6DA4","CDI"))
            _n=len(_series); _bw=0.8/_n
            for _k,(vals,cor,lbl) in enumerate(_series):
                _vv=[float(v) if v is not None else 0.0 for v in vals]
                axr.bar(_xs+(_k-(_n-1)/2)*_bw,_vv,_bw,color=cor,label=lbl,zorder=3)
            axr.axhline(0,color="#C9CFCB",linewidth=0.8)
            axr.set_xticks(_xs); axr.set_xticklabels([p[1] for p in _pers],color="#17271E",fontsize=9)
            axr.tick_params(colors="#17271E"); axr.spines[:].set_color("#D9E3DB")
            axr.yaxis.grid(True,color="#E4E8E7"); axr.set_axisbelow(True); axr.set_ylabel("%",color="#17271E")
            axr.legend(facecolor="#FFFFFF",edgecolor="#D9E3DB",labelcolor="#17271E",fontsize=8,loc="best")
            figr.tight_layout(pad=1)
            ibr=io.BytesIO(); figr.savefig(ibr,format="png",dpi=150,facecolor="#FFFFFF"); plt.close(figr); ibr.seek(0)
            elems.append(Image(ibr,width=15*cm,height=5.7*cm)); elems.append(Spacer(1,0.3*cm))
    except Exception:
        pass

    elems.append(Paragraph("Desvios por Indexador",s_sec))
    dd=[["Indexador","Atual (%)","Modelo (%)","Desvio (%)"]]
    for d in desvios: dd.append([d["label"],f'{d["real"]:.2f}',f'{d["alvo"]:.2f}',f'{d["desvio"]:+.2f}'])
    td=Table(dd,colWidths=[5*cm,3.5*cm,3.5*cm,3.5*cm])
    est=[("BACKGROUND",(0,0),(-1,0),DESC),("TEXTCOLOR",(0,0),(-1,0),PRETO),
         ("TEXTCOLOR",(0,1),(-1,-1),BRANCO),("FONTSIZE",(0,0),(-1,-1),8),
         ("ROWBACKGROUNDS",(0,1),(-1,-1),[CESC,CMED]),("GRID",(0,0),(-1,-1),0.3,colors.HexColor("#D9E3DB")),
         ("ALIGN",(1,0),(-1,-1),"CENTER"),("PADDING",(0,0),(-1,-1),4),("FONTNAME",(0,0),(-1,0),"Helvetica-Bold")]
    for i,d in enumerate(desvios,1):
        _ad=abs(d["desvio"])
        if _ad>=10:   est.append(("TEXTCOLOR",(3,i),(3,i),VERM))     # desvio grande (qualquer direção)
        elif _ad>=1.5:est.append(("TEXTCOLOR",(3,i),(3,i),AMARELO))  # desvio moderado
        else:         est.append(("TEXTCOLOR",(3,i),(3,i),VERDE))    # dentro da faixa
    td.setStyle(TableStyle(est))
    elems.append(td); elems.append(Spacer(1,0.3*cm))

    if alertas:
        elems.append(HRFlowable(width="100%",thickness=0.5,color=DESC,spaceAfter=4))
        elems.append(Paragraph("Alertas de Concentração",s_sec))
        for a in alertas: elems.append(Paragraph(a,S("Al",fontSize=9,leading=13,tc=AMARELO)))
        elems.append(Spacer(1,0.2*cm))

    if recomendacoes:
        elems.append(HRFlowable(width="100%",thickness=0.5,color=DESC,spaceAfter=4))
        elems.append(Paragraph(f"Por que estas recomendações, Modelo {modelo_lbl}",s_sec))
        elems.append(Paragraph(_texto_racional_modelo(modelo_lbl, perfil_lbl), s_body))
        elems.append(Spacer(1,0.25*cm))
        elems.append(Paragraph("Recomendações Fundamentadas",s_sec))
        for rec in recomendacoes:
            _falta = float(rec.get('falta_pp', 0) or 0)
            _valor = patrimonio * (_falta / 100.0)
            elems.append(Paragraph(
                f"{rec['urgencia']}, {rec['classe']} (falta {_falta:.1f}%) &nbsp;&nbsp;"
                f"<font size=14 color=\"#FFD966\"><b>{_fmt_brl(_valor)}</b></font>", s_bold))
            elems.append(Paragraph(rec["explicacao"],s_body))
            if rec.get("produtos"):
                prods=", ".join(rec["produtos"])
                elems.append(Paragraph(f"Produtos sugeridos: {prods} (sujeitos a disponibilidade, suitability e análise no líquido).",s_sug))
            elems.append(Spacer(1,0.15*cm))

    # ── Plano de Troca (venda → compra), MESMA fonte do 360°/tela (versão técnica) ──
    _pt = _plano_troca_resumo(plano_troca)
    if _pt and (_pt["reduzir"] or _pt["comprar"] or _pt["bloqueados"]):
        def _pesc(s):
            return str(s or "").replace("&","&amp;").replace("<","&lt;").replace(">","&gt;")
        _lim = _pt["limite_desagio"]
        elems.append(HRFlowable(width="100%",thickness=0.5,color=DESC,spaceAfter=4))
        elems.append(Paragraph("Plano de Troca, venda → compra",s_sec))
        elems.append(Paragraph(
            f"Total a realocar: <b>{_fmt_brl(_pt['total'])}</b>. Vende primeiro os ativos de pior rentabilidade; "
            f"deságio acima de {_lim:.0f}% em renda fixa/crédito privado não é realizado (ações e FIIs livres). "
            f"Compra: ações/FIIs por Markowitz-tangência; renda fixa em títulos diretos respeitando o FGC "
            f"(R$ 250k/emissor) e depois fundos.", s_body))
        elems.append(Paragraph("Vender / reduzir",s_bold))
        for it in _pt["reduzir"]:
            des = it.get("desagio")
            dtxt = (f" · no ano {des:+.1f}%") if des is not None else ""
            elems.append(Paragraph(f"{_pesc(it['nome'])} <font color=\"#888888\">({_pesc(it['label'])})</font>{dtxt} &nbsp; <b>{_fmt_brl(it['valor'])}</b>", s_sug))
        elems.append(Paragraph("Comprar / aplicar",s_bold))
        for it in _pt["comprar"]:
            det = (f" · {_pesc(it['detalhe'])}") if it.get("detalhe") else ""
            elems.append(Paragraph(f"{_pesc(it['nome'])} <font color=\"#888888\">({_pesc(it['label'])})</font>{det} &nbsp; <b>{_fmt_brl(it['valor'])}</b>", s_sug))
        if _pt["bloqueados"]:
            elems.append(Paragraph(f"Não vender agora, deságio acima de {_lim:.0f}% (renda fixa / crédito privado)",s_bold))
            for b in _pt["bloqueados"]:
                elems.append(Paragraph(f"{_pesc(b.get('nome'))} ({_pesc(b.get('label'))}), deságio de {abs(b.get('desagio',0) or 0):.1f}% no ano; manter e monitorar até recuperar.", s_sug))
        if _pt["previdencia"]:
            elems.append(Paragraph("Previdência, avaliar portabilidade (fora da venda automática)",s_bold))
            for p in _pt["previdencia"]:
                elems.append(Paragraph(f"{_pesc(p.get('nome'))} ({_pesc(p.get('label'))}), portabilidade, regime tributário, carência e IR.", s_sug))
        elems.append(Spacer(1,0.2*cm))

    # ── Posicionamento das ações + proteção de posições (Stock Guide Levante + XP)
    if acoes:
        guia = (carregar_stock_guide() or {}).get("acoes", {})
        def _rt(r):
            r=(r or "").upper()
            if "COMPRA" in r: return VERDE
            if "VENDA" in r:  return VERM
            if "NEUTRO" in r: return AMARELO
            return colors.HexColor("#AAAAAA")
        def _up(v):
            if v is None: return "n/d"
            pv=v*100
            return (f"+{pv:.0f}%" if pv>=0 else f"queda de {abs(pv):.0f}%")
        def _brl(v):
            return ("R$ "+f"{v:,.2f}".replace(",","X").replace(".",",").replace("X",".")) if v is not None else "n/d"
        linhas_pos=[["Ativo","% Cart.","Visão (Levante)","Preço-alvo","Upside","Consenso (XP)"]]
        estilo_extra=[]; prot_itens=[]; i=0
        for a in acoes:
            _peso=float(a.get("perc",0) or 0)
            if _peso < 0.1:   # remove posições irrelevantes (0,0%)
                continue
            i+=1
            tk=str(a.get("ticker","")).upper()
            g=guia.get(tk) or {}
            lev=g.get("levante"); xp=g.get("xp"); src=lev or xp
            visao_txt=(lev.get("rating") if lev else ((xp.get("rating","")+" (via XP)") if xp else "sem cobertura"))
            alvo_txt=_brl(src.get("alvo")) if (src and src.get("alvo") is not None) else "n/d"
            up_txt=_up(src.get("upside")) if src else "n/d"
            cons_txt=((xp.get("consenso") or xp.get("rating","") or "n/d") if xp else "n/d")
            linhas_pos.append([tk, f'{_peso:.1f}%', visao_txt, alvo_txt, up_txt, cons_txt])
            estilo_extra.append(("TEXTCOLOR",(2,i),(2,i),_rt(lev.get("rating") if lev else (xp.get("rating") if xp else ""))))
            if src and src.get("upside") is not None and src.get("upside")<=0.10:
                prot_itens.append({"ticker":tk,"rating":(lev.get("rating") if lev else xp.get("rating")),
                    "fonte":("Levante" if lev else "XP"),"alvo":src.get("alvo"),"upside":src.get("upside")})
        if len(linhas_pos) > 1:
            elems.append(HRFlowable(width="100%",thickness=0.5,color=DESC,spaceAfter=4))
            elems.append(Paragraph("Posicionamento das Ações, Levante (casa principal) + XP (visão de mercado)",s_sec))
            tp=Table(linhas_pos,colWidths=[2.3*cm,1.6*cm,3.8*cm,2.6*cm,2.6*cm,3.6*cm])
            est_pos=[("BACKGROUND",(0,0),(-1,0),DESC),("TEXTCOLOR",(0,0),(-1,0),PRETO),
                     ("TEXTCOLOR",(0,1),(-1,-1),BRANCO),("FONTSIZE",(0,0),(-1,-1),7.5),
                     ("ROWBACKGROUNDS",(0,1),(-1,-1),[CESC,CMED]),("GRID",(0,0),(-1,-1),0.3,colors.HexColor("#D9E3DB")),
                     ("ALIGN",(1,0),(1,-1),"CENTER"),("ALIGN",(3,0),(4,-1),"CENTER"),
                     ("PADDING",(0,0),(-1,-1),3),("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),
                     ("TEXTCOLOR",(0,1),(0,-1),DOURADO),("VALIGN",(0,0),(-1,-1),"MIDDLE")]
            est_pos+=estilo_extra
            tp.setStyle(TableStyle(est_pos))
            elems.append(tp); elems.append(Spacer(1,0.15*cm))
            elems.append(Paragraph("A visão Levante é uma das referências externas desta análise e não substitui a avaliação individual do assessor. O preço-alvo é referência; o preço vigente vem do XPerformance.",s_gest))
            elems.append(Spacer(1,0.3*cm))

        if prot_itens:
            status_por_ticker={}
            if conta:
                try:
                    _fic=load_fichas()
                    _f=_fic.get(f"conta:{conta}") or _fic.get(conta) or {}
                    for _p in _f.get("protecoes",[]):
                        status_por_ticker[_p.get("ticker")]=_p.get("status","pendente")
                except Exception:
                    pass
            STATUS_LBL={"pendente":"Pendente","recusada":"Cliente recusou","estruturada":"Estruturada aplicada","caixa":"Vendido p/ caixa"}
            elems.append(HRFlowable(width="100%",thickness=0.5,color=DESC,spaceAfter=4))
            elems.append(Paragraph("Proteção de posições, perto do preço-alvo",s_sec))
            elems.append(Paragraph("Ações a 10% ou menos do preço-alvo. Formas de proteger o ganho: (a) operação estruturada (collar, put de proteção ou fence), que envolve custo, prazo e limitação de ganho, exigindo suitability; ou (b) realizar parte da posição e alocar em caixa (pós-fixado). A decisão considera preço, tributação e o objetivo do cliente.",s_body))
            elems.append(Spacer(1,0.1*cm))
            for it in prot_itens:
                st=STATUS_LBL.get(status_por_ticker.get(it["ticker"],"pendente"),"Pendente")
                elems.append(Paragraph(f'{it["ticker"]}, {it["rating"]} ({it["fonte"]}) · alvo {_brl(it["alvo"])} (upside {_up(it["upside"])}) · Status: {st}',
                    S("Prot",fontSize=9,leading=13,tc=LARANJA)))
            elems.append(Spacer(1,0.3*cm))

    elems.append(HRFlowable(width="100%",thickness=0.5,color=DESC,spaceAfter=4))
    elems.append(Paragraph(f"Consenso dos Gestores, Ref. {ref_contexto}",s_sec))
    elems.append(Paragraph("Convergência: o pós-fixado segue atrativo, mas não deve dominar; a inflação (NTN-B) é a oportunidade do momento, com juro real elevado; o internacional atua como diversificação cambial; e há cautela com alternativos ilíquidos para perfis conservadores.",s_body))
    elems.append(Spacer(1,0.5*cm))

    # ── Estratégia de realocação (transição)
    elems.append(HRFlowable(width="100%",thickness=0.5,color=DESC,spaceAfter=4))
    elems.append(Paragraph("Estratégia de realocação",s_sec))
    elems.append(Paragraph(
        "A transição parte da redução das concentrações identificadas, sobretudo em renda variável, em direção às classes "
        "sub-alocadas: pós-fixado, inflação (IPCA+) e internacional. A execução deve ser gradual e está sempre condicionada à "
        "validação tributária, ao preço e à liquidez de cada posição e à anuência do cliente. Os valores por classe indicados "
        "nas recomendações são referência de destino, não ordens de execução.", s_body))
    elems.append(Spacer(1,0.3*cm))

    # ── Plano de ação recomendado (página final)
    elems.append(PageBreak())
    elems.append(Paragraph("Plano de ação recomendado",s_sec))
    for _t,_d in [
        ("Etapa 1, Diagnóstico completo","Consolidar o patrimônio total (inclusive fora da XP), validar objetivos, prazos e a liquidez necessária."),
        ("Etapa 2, Redução de concentração","Revisar as maiores posições em renda variável, definindo realização imediata ou gradual e avaliando os impactos tributários."),
        ("Etapa 3, Reequilíbrio","Elevar o pós-fixado, introduzir proteção inflacionária (IPCA+) e diversificação internacional, e avaliar parcela complementar em multimercados."),
        ("Etapa 4, Acompanhamento","Revisão periódica, rebalanceamento por faixa e atualização dos objetivos."),
    ]:
        elems.append(Paragraph(_t, s_olh_h))
        elems.append(Paragraph(_d, s_body))
    elems.append(Spacer(1,0.25*cm))
    elems.append(Paragraph("A implementação depende da validação dos objetivos, do patrimônio consolidado, da análise tributária, das condições de mercado e da aprovação expressa do cliente.", s_bold))
    elems.append(Spacer(1,0.3*cm))

    # ── Metodologia e fontes
    elems.append(HRFlowable(width="100%",thickness=0.5,color=DESC,spaceAfter=4))
    elems.append(Paragraph("Metodologia e fontes",s_sec))
    elems.append(Paragraph(
        f"Modelo de referência: {modelo_lbl}, alocação estratégica por indexador aplicada ao perfil {perfil_lbl}"
        + (f", data-base {data_ref}" if data_ref else "") + ". "
        "A análise considera a carteira mantida na XP; posições fora da XP ainda não estão consolidadas "
        "(Open Finance/Open Investment em implantação) e devem ser incorporadas para uma recomendação completa. "
        "Dados macroeconômicos via Banco Central do Brasil (BCB). Visão dos gestores consolidada de cartas mensais públicas.",
        s_gest))
    elems.append(Spacer(1,0.3*cm))

    # ── Disclaimer (versão do cliente)
    elems.append(HRFlowable(width="100%",thickness=0.5,color=DESC,spaceAfter=4))
    elems.append(Paragraph(
        "Este material tem caráter informativo e não constitui recomendação individualizada de investimento, oferta ou promessa "
        "de rentabilidade. Rentabilidade passada não garante resultados futuros. A adequação de qualquer produto depende do perfil "
        "(suitability), dos objetivos e da situação financeira do investidor. Braúna Investimentos, escritório vinculado à XP Investimentos.",
        S("Disc",fontSize=8,leading=11,tc=colors.HexColor("#5A6A60"),alignment=TA_CENTER)))

    def fundo(canvas,doc):
        canvas.saveState(); canvas.setFillColor(colors.HexColor("#FBFBFA"))
        canvas.rect(0,0,A4[0],A4[1],fill=1,stroke=0); canvas.restoreState()

    # Marcador invisível: registra em que página e altura o conteúdo terminou.
    class _PosMarker(Flowable):
        def __init__(self): Flowable.__init__(self); self.page=0; self.y=0
        def wrap(self, aw, ah): return (0, 0)
        def draw(self): pass
        def drawOn(self, canvas, x, y, _sW=0): self.page=canvas.getPageNumber(); self.y=y
    marcador=_PosMarker(); elems.append(marcador)

    # Coleta estilos e espaçadores para eventual compactação
    _estilos, _spacers = set(), []
    for f in elems:
        st=getattr(f,"style",None)
        if st is not None and hasattr(st,"spaceAfter"): _estilos.add(st)
        if isinstance(f,Spacer): _spacers.append(f)

    frame_h=A4[1]-4*cm; topo=A4[1]-2*cm
    doc.build(list(elems),onFirstPage=fundo,onLaterPages=fundo)

    # Se a última página encerrou com <10% preenchida, compacta e refaz numa página cheia
    try:
        if marcador.page and marcador.page>1 and frame_h>0:
            fill=(topo-marcador.y)/frame_h
            if fill < 0.10:
                for st in _estilos:
                    if getattr(st,"spaceBefore",None) is not None: st.spaceBefore*=0.25
                    if getattr(st,"spaceAfter",None)  is not None: st.spaceAfter*=0.25
                    st.leading=max(getattr(st,"fontSize",9)+0.6, getattr(st,"leading",12)*0.82)
                for s in _spacers:
                    try: s.height*=0.2
                    except Exception: pass
                buf2=io.BytesIO()
                doc2=SimpleDocTemplate(buf2,pagesize=A4,leftMargin=2*cm,rightMargin=2*cm,topMargin=1.3*cm,bottomMargin=1.3*cm)
                doc2.build(list(elems),onFirstPage=fundo,onLaterPages=fundo)
                buf2.seek(0); return buf2
    except Exception:
        pass

    buf.seek(0); return buf


# ═══════════════════════════════════════════════════════════════════════════════
#  BRAÚNA 360°, Check-up Patrimonial (documento premium do cliente, HTML)
# ═══════════════════════════════════════════════════════════════════════════════
def _b360_esc(s):
    return (str(s) if s is not None else "").replace("&","&amp;").replace("<","&lt;").replace(">","&gt;")

def _b360_brl(v):
    try: return "R$ " + f"{float(v):,.2f}".replace(",","X").replace(".",",").replace("X",".")
    except Exception: return "R$ 0,00"

def _raio_x(comp, alvo, rent, checklist=None):
    """9 dimensões do Raio-X Patrimonial. Financeiras vêm da carteira; as 'soft'
    (planejamento/sucessão/tributação) vêm do checklist Modelo de Servir se houver."""
    def cl(v, lo=15, hi=98): return int(max(lo, min(hi, round(v))))
    pos  = comp.get("pos_fixado",0) or 0; infl = comp.get("inflacao",0) or 0
    intl = comp.get("internacional",0) or 0; fiis = comp.get("fiis",0) or 0
    caixa= comp.get("caixa",0) or 0
    a_intl = alvo.get("internacional",9) or 9; a_infl = alvo.get("inflacao",23) or 23
    nclasses = sum(1 for c in CATS if (comp.get(c,0) or 0) >= 3)
    maior = max([comp.get(c,0) or 0 for c in CATS] + [0])
    sc = {}
    sc["Proteção inflação"] = cl(infl/max(a_infl,1)*86)
    sc["Liquidez"]          = cl(45 + (pos+caixa)*0.85)
    sc["Diversificação"]    = cl(46 + nclasses*7 - max(0,maior-45)*0.7)
    sc["Renda recorrente"]  = cl(45 + fiis*4 + infl*0.3)
    sc["Internacional"]     = cl(20 + intl/max(a_intl,1)*72)
    # soft
    soft = {"Tributação":70, "Sucessão":55, "Planejamento":52, "Relacionamento":88}
    if checklist:
        pares = [(str(p.get("nome","")).lower(), p.get("status")=="ok") for p in checklist]
        def _s(key, yes, no):
            for nm,ok in pares:
                if key in nm: return yes if ok else no
            return (yes+no)//2
        soft["Planejamento"] = _s("plan", 88, 45)
        soft["Sucessão"]     = _s("suces", 85, 48)
        soft["Tributação"]   = _s("tribut", 85, 62)
    sc.update(soft)
    ordem = ["Proteção inflação","Liquidez","Relacionamento","Tributação","Diversificação",
             "Renda recorrente","Sucessão","Planejamento","Internacional"]
    dims = [(k, sc[k]) for k in ordem if k in sc]
    geral = cl(sum(v for _,v in dims)/len(dims))
    return dims, geral

def _b360_narrativa(comp, alvo, rent, dims_geral):
    """Deriva achados, pontos de atenção e prioridades a partir dos gaps reais."""
    lbl = lambda c: LABELS.get(c, c)
    sub  = sorted([(c, (alvo.get(c,0) or 0)-(comp.get(c,0) or 0)) for c in CATS
                   if (alvo.get(c,0) or 0)-(comp.get(c,0) or 0) >= 5], key=lambda x:-x[1])
    sobre= sorted([(c, (comp.get(c,0) or 0)-(alvo.get(c,0) or 0)) for c in CATS
                   if (comp.get(c,0) or 0)-(alvo.get(c,0) or 0) >= 5], key=lambda x:-x[1])
    infl = comp.get("inflacao",0) or 0; intl = comp.get("internacional",0) or 0
    p12 = (rent.get("portfolio") or {}).get("12m"); c12 = (rent.get("cdi") or {}).get("12m")
    supera = (p12 is not None and c12 is not None and p12 > c12)
    achados = []
    if infl >= (alvo.get("inflacao",23) or 23)*0.8:
        achados.append(("g","Boa proteção contra a inflação",
            f"{infl:.0f}% do patrimônio em IPCA+ preservam o poder de compra num juro real historicamente alto."))
    if supera:
        achados.append(("g","Rentabilidade acima do CDI",
            f"+{p12:.1f}% em 12 meses contra ~{c12:.1f}% do CDI, retorno consistente."))
    if sobre:
        c,g = sobre[0]
        achados.append(("y",f"Concentração em {lbl(c).lower()}",
            f"{comp.get(c,0):.0f}% em um único bloco. Concentra o resultado num só fator de risco."))
    if intl < 5:
        achados.append(("y","Sem diversificação internacional",
            "A exposição global está abaixo do adequado, o patrimônio depende quase só do Brasil e do real."))
    achados.append(("r","Planejamento e sucessão a estruturar",
        "A carteira está boa; a estrutura patrimonial ao redor dela ainda pode ser desenhada."))
    achados = achados[:5]
    # pontos de atenção
    atencao = []
    if sobre:
        c,g = sobre[0]
        atencao.append({"t":f"Exposição concentrada em {lbl(c).lower()}","p":"alta",
            "imp":"Médio","prob":"Alta no ciclo de queda","hz":"12 meses",
            "rec":f"Realocar gradualmente para IPCA+ e pré-fixado tático."})
    if intl < 5:
        atencao.append({"t":"Ausência de exposição internacional","p":"alta",
            "imp":"Alto","prob":"Estrutural","hz":"90 dias",
            "rec":"Iniciar 5–9% em dólar de forma gradual, via liquidez excedente."})
    atencao.append({"t":"Planejamento financeiro e sucessório","p":"alta",
        "imp":"Alto","prob":"Certa","hz":"Contínuo",
        "rec":"Consolidar o patrimônio total e desenhar a estrutura sucessória."})
    # prioridades
    prioridades = [
        ("Planejamento financeiro","A base de tudo, objetivos, prazos e liquidez consolidados antes de qualquer troca."),
        ("Diversificação internacional","Reduz a dependência exclusiva do Brasil e protege contra a desvalorização do real."),
    ]
    if sobre:
        c,_ = sobre[0]
        prioridades.append((f"Reduzir concentração em {lbl(c).lower()}",
            "Migrar parte para IPCA+ e pré-fixado, aproveitando o juro real elevado."))
    prioridades += [
        ("Planejamento sucessório","Organizar a transmissão do patrimônio com agilidade e menor atrito."),
        ("Revisão tributária","Comparar sempre pelo líquido e capturar as isenções cabíveis ao perfil."),
    ]
    return achados, atencao, prioridades[:5], supera

