_FGC_INSTR = ("CDB", "RDB", "LCI", "LCA", "LCD")  # instrumentos com cobertura do FGC
def _fgc_emissor(nome):
    """Retorna o emissor normalizado se o ativo for RF bancária elegível ao FGC; senão None.
    Deriva do próprio nome do XPerformance (ex.: 'CDB Banco BBC (Grupo Simpar) - JUN/2028')."""
    if not nome:
        return None
    u = nome.upper()
    instr = next((k for k in _FGC_INSTR if re.search(r"\b" + k + r"\b", u) or u.replace(" ", "").startswith(k)), None)
    if not instr:
        return None
    # texto após o instrumento, antes do sufixo de vencimento (" - MES/ANO" ou data)
    resto = u.split(instr, 1)[1] if instr in u else u
    resto = re.sub(r"\([^)]*\)", " ", resto)  # remove "(Grupo Simpar)" etc. para agrupar o mesmo emissor
    resto = re.split(r"\s[-–]\s|\b(?:JAN|FEV|MAR|ABR|MAI|JUN|JUL|AGO|SET|OUT|NOV|DEZ)[/ ]?20\d\d|\d{2}/\d{2}/20\d\d", resto)[0]
    resto = re.sub(r"[^A-ZÀ-Ú0-9 &]", " ", resto)
    palavras = [p for p in resto.split() if p not in ("S", "A", "SA", "CFI", "FINANCEIRA", "BANCO", "S.A", "DE", "DO", "DA", "CONSIGNADO")]
    emissor = " ".join(palavras[:2]).strip()
    return emissor or instr

def alertas_fgc(rf_ativos):
    """Exposição FGC ATUAL por emissor (soma de saldo dos ativos elegíveis). Alerta > R$ 250k.
    Projeção futura não é feita: o XPerformance não traz a taxa contratada (só rentabilidade)."""
    LIM = 250000.0
    por_emissor = {}
    for a in rf_ativos:
        emis = _fgc_emissor(a.get("nome", ""))
        if emis and (a.get("saldo") or 0) > 0:
            por_emissor[emis] = por_emissor.get(emis, 0.0) + float(a["saldo"])
    def _brl(v):
        return "R$ " + f"{v:,.0f}".replace(",", ".")
    out = []
    for emis, total in sorted(por_emissor.items(), key=lambda x: -x[1]):
        if total > LIM:
            out.append({
                "tipo": "fgc", "nivel": "alto", "classe": "pos_fixado",
                "msg": f"FGC: exposição de {_brl(total)} em {emis.title()} — acima do limite de R$ 250 mil. Excedente de {_brl(total-LIM)} é risco direto do emissor, sem garantia do FGC.",
            })
        elif total >= 225000:
            out.append({
                "tipo": "fgc", "nivel": "medio", "classe": "pos_fixado",
                "msg": f"FGC: exposição de {_brl(total)} em {emis.title()} — próximo do limite de R$ 250 mil. Evitar novos aportes neste emissor.",
            })
    return out

def gerar_diagnosticos(xp_parsed, perfil=""):
    """Gera diagnósticos automáticos a partir dos ativos individuais do XPerformance."""
    rf_ativos  = xp_parsed.get("rf_ativos", [])
    acoes_list = xp_parsed.get("acoes", [])
    fiis_list  = xp_parsed.get("fiis", [])
    comp       = xp_parsed.get("comp", {})
    alertas    = []

    # Exposição ao FGC por emissor (atual)
    alertas.extend(alertas_fgc(rf_ativos))

    # Concentração em ativo único de RF > 8%
    for ativo in rf_ativos:
        if ativo.get("perc", 0) > 8:
            nivel = "alto" if ativo["perc"] > 15 else "medio"
            alertas.append({
                "tipo": "concentracao_rf", "nivel": nivel,
                "msg": f"Concentração alta: {ativo['nome'][:45]} representa {ativo['perc']:.1f}% da carteira",
                "ativo": ativo["nome"], "classe": ativo.get("classe",""),
            })

    # Ativo RF com rentabilidade negativa no mês
    for ativo in rf_ativos:
        rm = ativo.get("rent_mes")
        if rm is not None and rm < 0:
            alertas.append({
                "tipo": "rentabilidade_negativa", "nivel": "alto",
                "msg": f"Rentabilidade negativa: {ativo['nome'][:45]} ({rm:+.2f}% no mês)",
                "ativo": ativo["nome"], "classe": ativo.get("classe",""),
            })

    # Ativo RF com rentabilidade muito baixa no mês (< 0.3%)
    for ativo in rf_ativos:
        rm = ativo.get("rent_mes")
        if rm is not None and 0 <= rm < 0.3:
            alertas.append({
                "tipo": "rentabilidade_baixa", "nivel": "medio",
                "msg": f"Rentabilidade abaixo da média: {ativo['nome'][:45]} ({rm:.2f}% no mês — verifique custo vs CDI)",
                "ativo": ativo["nome"], "classe": ativo.get("classe",""),
            })

    # Concentração em ação única > 5%
    for ativo in acoes_list:
        if ativo.get("perc", 0) > 5:
            alertas.append({
                "tipo": "concentracao_rv", "nivel": "medio",
                "msg": f"Posição relevante em ação: {ativo['ticker']} = {ativo['perc']:.1f}% da carteira",
                "ativo": ativo["ticker"], "classe": "acoes",
            })

    # Gap vs SAA da casa (Braúna) por classe — régua do rebalanceamento.
    # Fallback para o modelo antigo (HP_PORTFOLIOS_DEFAULT) se não houver SAA p/ o perfil.
    alvo = saa_alvo(perfil)
    if alvo:
        fonte_alvo = f"alvo Braúna {perfil.replace('_',' ').title()}"
    elif perfil and perfil in HP_PORTFOLIOS_DEFAULT.get("perfis", {}):
        alvo = HP_PORTFOLIOS_DEFAULT["perfis"][perfil]
        fonte_alvo = f"modelo {perfil.replace('_',' ').title()}"
    else:
        alvo = {}
        fonte_alvo = ""
    if alvo:
        for cat in CATS:
            gap = comp.get(cat, 0) - alvo.get(cat, 0)
            if abs(gap) >= 5:
                direcao = "acima" if gap > 0 else "abaixo"
                alertas.append({
                    "tipo": "gap_saa", "nivel": "alto" if abs(gap) >= 10 else "medio",
                    "msg": f"{LABELS.get(cat, cat)}: {comp.get(cat,0):.1f}% ({gap:+.1f}% {direcao} do {fonte_alvo})",
                    "classe": cat,
                })

    # Subalocação internacional — proteção cambial / risco Brasil (zonas críticas).
    # Acima de 5% o gap vs SAA já cobre; aqui reforça a faixa de subproteção.
    if perfil:
        intl = comp.get("internacional", 0)
        if intl <= 0:
            alertas.append({
                "tipo": "subalocacao_intl", "nivel": "alto", "classe": "internacional",
                "msg": "Internacional 0%: cliente 100% exposto ao Brasil e ao real. Avaliar posição mínima em dólar usando liquidez excedente ou vencimentos próximos.",
            })
        elif intl < 5:
            alertas.append({
                "tipo": "subalocacao_intl", "nivel": "medio", "classe": "internacional",
                "msg": f"Internacional {intl:.1f}% (abaixo de 5%): pode estar subprotegido contra risco Brasil, câmbio e inflação importada — mesmo em perfil conservador.",
            })

    # Diversificação mínima
    classes_com_posicao = sum(1 for v in comp.values() if v >= 1.0)
    if classes_com_posicao < 3:
        alertas.append({
            "tipo": "diversificacao", "nivel": "alto",
            "msg": f"Carteira com apenas {classes_com_posicao} classe(s) de ativos — risco de concentração sistêmica.",
        })

    # Resumo numérico da posição
    total_rf   = sum(a.get("saldo", 0) for a in rf_ativos)
    total_rv   = sum(a.get("saldo", 0) for a in acoes_list)
    total_fiis = sum(a.get("saldo", 0) for a in fiis_list)

    return {
        "alertas": alertas,
        "rf_ativos":  rf_ativos,
        "acoes":      acoes_list,
        "fiis":       fiis_list,
        "total_rf":   round(total_rf, 2),
        "total_rv":   round(total_rv, 2),
        "total_fiis": round(total_fiis, 2),
        "qtd_ativos": len(rf_ativos) + len(acoes_list) + len(fiis_list),
    }


def _perfil_cards_html():
    """Gera os cards de seleção de perfil renderizados no servidor."""
    PERFIS_UI = [
        {"key":"super_conservadora","lbl":"Super Conservadora","emoji":"&#128737;","cor":"#1F9D77","desc":"Preservação de capital"},
        {"key":"conservadora",      "lbl":"Conservadora",      "emoji":"&#127974;","cor":"#A8833C","desc":"Renda segura"},
        {"key":"moderada",          "lbl":"Moderada",          "emoji":"&#9878;",  "cor":"#2E86B8","desc":"Equilíbrio"},
        {"key":"arrojada",          "lbl":"Arrojada",          "emoji":"&#128200;","cor":"#C0673A","desc":"Crescimento"},
        {"key":"agressiva",         "lbl":"Agressiva",         "emoji":"&#128640;","cor":"#D93B3B","desc":"Alto crescimento"},
    ]
    GRUPOS = [
        {"chaves":["pos_fixado","inflacao","pre_fixado"],"cor":"#A8833C","lbl":"RF"},
        {"chaves":["acoes","fiis"],                      "cor":"#4E63C8","lbl":"RV"},
        {"chaves":["multimercado"],                      "cor":"#1F9D77","lbl":"Multi"},
        {"chaves":["internacional"],                     "cor":"#E88B8B","lbl":"Intl"},
        {"chaves":["alternativos","criptomoedas"],        "cor":"#B8A0E8","lbl":"Alt"},
    ]
    html_parts = []
    for i, p in enumerate(PERFIS_UI):
        m = HP_PORTFOLIOS_DEFAULT["perfis"].get(p["key"], MODELOS.get(p["key"], {}))
        # Mini barra empilhada
        bar_segs = ""
        for g in GRUPOS:
            pct = sum(float(m.get(k, 0) or 0) for k in g["chaves"])
            if pct > 0.5:
                bar_segs += f'<div title="{g["lbl"]} {pct:.0f}%" style="flex:{pct};background:{g["cor"]};height:100%;border-radius:2px"></div>'
        # Todas as alocações > 0
        itens = sorted([(k,v) for k,v in m.items() if isinstance(v,(int,float)) and v>0 and k!="label"], key=lambda x: -x[1])
        top_html = "".join(
            f'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:2px">'
            f'<span style="font-size:13px;color:#39493F">{LABELS.get(k,k)}</span>'
            f'<span style="font-size:13px;font-weight:700;color:#8A6A28">{v}%</span>'
            f'</div>'
            for k,v in itens[:4]
        )
        # "moderada" é o default selecionado
        is_default = (p["key"] == "moderada")
        border_style = f'2px solid {p["cor"]}' if is_default else '2px solid #EAF4EC'
        bg_style = f'{p["cor"]}15' if is_default else '#EFF3EF'
        badge = f'<div class="perfil-sel-badge" style="position:absolute;top:5px;right:6px;font-size:12px;color:{p["cor"]};font-weight:700;display:{"block" if is_default else "none"}">&#10003; SELECIONADO</div>'
        card = (
            f'<div onclick="selecionarPerfil(\'{p["key"]}\')" data-perfil="{p["key"]}" data-cor="{p["cor"]}" class="perfil-card-item" style="'
            f'background:{bg_style};border:{border_style};border-radius:10px;padding:14px 18px;'
            f'cursor:pointer;flex:1 1 0;min-width:200px;max-width:none;position:relative;overflow:hidden;transition:all .15s;box-sizing:border-box">'
            f'{badge}'
            f'<div style="font-size:22px;margin-bottom:4px">{p["emoji"]}</div>'
            f'<div class="perfil-card-nome" style="font-size:15px;font-weight:700;color:{"" + p["cor"] if is_default else "#0A0F0C"};margin-bottom:2px;line-height:1.2">{p["lbl"]}</div>'
            f'<div style="font-size:13px;color:#39493F;margin-bottom:8px">{p["desc"]}</div>'
            f'<div style="display:flex;height:5px;border-radius:3px;overflow:hidden;background:#EFF3EF;margin-bottom:8px;gap:1px">{bar_segs}</div>'
            f'<div>{top_html}</div>'
            f'</div>'
        )
        html_parts.append(card)
    return "\n".join(html_parts)

