@app.route("/api/clientes-resumo", methods=["GET"])
def clientes_resumo():
    """Resumo dos clientes salvos de um assessor: por perfil (com contagem) e
    quais estão DESENQUADRADOS (perfil detectado pela carteira ≠ perfil atribuído)."""
    assessor = request.args.get("assessor", "").lower().strip()
    fichas = load_fichas()
    hist   = load_hist()
    lista, seen = [], set()
    for k, v in fichas.items():
        if not isinstance(v, dict):
            continue
        if not (k.startswith(assessor + "|") or v.get("assessor", "").lower() == assessor):
            continue
        conta = str(v.get("conta", "")).strip()
        dedup = conta or k
        if dedup in seen:
            continue
        seen.add(dedup)
        perfil = (v.get("perfil", "") or "").lower().strip()
        # Última composição salva (histórico) — entradas mais recentes primeiro
        comp = {}
        hentry = hist.get(f"conta:{conta}") or hist.get(conta) or hist.get(k)
        if hentry:
            ents = hentry.get("entradas") if isinstance(hentry, dict) else hentry
            if ents:
                comp = ents[0].get("composicao") or ents[-1].get("composicao") or {}
        perfil_det = _sugerir_perfil_por_composicao(comp) if comp else ""
        desenq = bool(perfil and perfil_det and perfil_det != perfil)
        lista.append({
            "conta": conta, "nome": v.get("nome", ""), "perfil": perfil,
            "gestora_nome": v.get("gestora_nome", ""), "data_ultimo_xp": v.get("data_ultimo_xp", ""),
            "assessor": v.get("assessor", ""),
            "perfil_detectado": perfil_det, "desenquadrado": desenq,
        })
    lista.sort(key=lambda c: (c.get("perfil", ""), (c.get("nome", "") or c.get("conta", "")).lower()))
    return jsonify({"total": len(lista), "clientes": lista,
                    "desenquadrados": sum(1 for c in lista if c["desenquadrado"])})

@app.route("/api/mercado-ticker", methods=["GET"])
def mercado_ticker():
    """Últimas do mercado para o ticker do topo: índices/câmbio (Yahoo Finance)
    + macro (BCB). Cacheado em memória por 10 min."""
    import time as _t, urllib.request as _ur, json as _j
    cache = mercado_ticker.__dict__.setdefault("_cache", {"ts": 0, "itens": []})
    if cache["itens"] and (_t.time() - cache["ts"] < 600):
        return jsonify({"itens": cache["itens"]})

    itens = []
    HEAD = {"User-Agent": "Mozilla/5.0 (compatible; Brauna/1.0)", "Accept": "application/json"}
    ativos = [("^BVSP","Ibovespa","idx"),("USDBRL=X","Dólar","brl"),
              ("^GSPC","S&P 500","idx"),("BTC-USD","Bitcoin","usd")]
    def _milhar(v):
        return f"{v:,.0f}".replace(",", ".")
    for sym, nome, tipo in ativos:
        try:
            url = f"https://query1.finance.yahoo.com/v8/finance/chart/{sym}?range=1d&interval=1d"
            with _ur.urlopen(_ur.Request(url, headers=HEAD), timeout=5) as r:
                raw = _j.loads(r.read().decode("utf-8"))
            meta = raw["chart"]["result"][0]["meta"]
            prc  = meta.get("regularMarketPrice") or meta.get("chartPreviousClose")
            prev = meta.get("previousClose") or meta.get("chartPreviousClose") or prc
            if not prc:
                continue
            var  = round((prc/prev - 1)*100, 2) if prev else 0.0
            seta = "▲" if var >= 0 else "▼"
            if tipo == "brl":  val = f"R$ {prc:.2f}".replace(".", ",")
            elif tipo == "usd": val = f"US$ {_milhar(prc)}"
            else:               val = _milhar(prc)
            var_txt = f"{abs(var):.2f}".replace(".", ",")
            itens.append(f"{nome} {val} {seta} {var_txt}%")
        except Exception:
            continue
    try:
        m = buscar_macro_bcb()
        if m.get("selic_meta"): itens.append(f"Selic {m['selic_meta']:.2f}%".replace(".", ","))
        if m.get("ipca_12m"):   itens.append(f"IPCA 12M {m['ipca_12m']:.2f}%".replace(".", ","))
    except Exception:
        pass
    if itens:
        cache["itens"] = itens; cache["ts"] = _t.time()
    return jsonify({"itens": itens or cache["itens"]})

# Universo líquido para o painel de destaques (maiores altas do dia)
_DESTAQUES_ACOES = ["PETR4","PETR3","VALE3","ITUB4","BBAS3","BBDC4","B3SA3","ABEV3","WEGE3","ITSA4",
    "BPAC11","RENT3","PRIO3","RADL3","RAIL3","SUZB3","GGBR4","CSNA3","USIM5","ELET3",
    "EQTL3","ENEV3","CMIG4","VBBR3","RDOR3","HAPV3","LREN3","VIVT3","TIMS3","TOTS3",
    "EMBR3","CVCB3","CYRE3","MRVE3","BBSE3","CXSE3","ASAI3","NTCO3","KLBN11","SBSP3"]
_DESTAQUES_FIIS = ["HGLG11","KNRI11","MXRF11","XPML11","VISC11","HGRU11","KNCR11","KNIP11","HGBS11","VILG11",
    "XPLG11","BTLG11","RECR11","KNSC11","HGRE11","RBRR11","VGHF11","MCCI11","IRDM11","GGRC11",
    "RZTR11","TGAR11","HFOF11","BRCO11","JSRE11","ALZR11","TRXF11","CPTS11","BCFF11","PVBI11"]

def _quote_yahoo_simples(sym_b3: str):
    """Cotação de um ticker B3 via Yahoo (v8 chart). Retorna dict ou None."""
    import urllib.request as _ur, json as _j
    HEAD = {"User-Agent": "Mozilla/5.0 (compatible; Brauna-Mesas/1.0)", "Accept": "application/json"}
    url = f"https://query1.finance.yahoo.com/v8/finance/chart/{sym_b3}.SA?range=1d&interval=1d"
    try:
        with _ur.urlopen(_ur.Request(url, headers=HEAD), timeout=4) as r:
            raw = _j.loads(r.read().decode("utf-8"))
        meta = raw["chart"]["result"][0]["meta"]
        prc  = meta.get("regularMarketPrice") or meta.get("chartPreviousClose")
        prev = meta.get("previousClose") or meta.get("chartPreviousClose") or prc
        if not prc or not prev:
            return None
        return {"ticker": sym_b3, "preco": round(float(prc), 2),
                "variacao": round((prc/prev - 1)*100, 2),
                "nome": meta.get("shortName") or meta.get("longName") or sym_b3}
    except Exception:
        return None

@app.route("/api/mercado-destaques", methods=["GET"])
def mercado_destaques():
    """Painel de destaques: top 5 ações e top 5 FIIs em maior alta no dia + dólar.
    Busca o universo líquido em paralelo (Yahoo). Cache em memória por 15 min."""
    import time as _t
    from concurrent.futures import ThreadPoolExecutor
    cache = mercado_destaques.__dict__.setdefault("_cache", {"ts": 0, "data": None})
    if cache["data"] and (_t.time() - cache["ts"] < 900):
        return jsonify(cache["data"])

    universo = _DESTAQUES_ACOES + _DESTAQUES_FIIS
    cot = {}
    try:
        with ThreadPoolExecutor(max_workers=20) as ex:
            for res in ex.map(_quote_yahoo_simples, universo):
                if res:
                    cot[res["ticker"]] = res
    except Exception:
        pass

    def _top(lista):
        vals = [cot[t] for t in lista if t in cot]
        vals.sort(key=lambda x: x["variacao"], reverse=True)
        return vals[:5]

    # Dólar (mesma fonte do ticker)
    dolar = None
    d = _quote_yahoo_simples_par("USDBRL=X")
    if d:
        dolar = {"preco": d["preco"], "variacao": d["variacao"]}

    data = {
        "acoes":     _top(_DESTAQUES_ACOES),
        "fiis":      _top(_DESTAQUES_FIIS),
        "dolar":     dolar,
        "atualizado": agora_br().strftime("%d/%m %H:%M"),
    }
    if data["acoes"] or data["fiis"]:
        cache["data"] = data; cache["ts"] = _t.time()
    return jsonify(data)

def _quote_yahoo_simples_par(sym_full: str):
    """Cotação de um símbolo Yahoo completo (ex.: USDBRL=X) — sem sufixo .SA."""
    import urllib.request as _ur, json as _j
    HEAD = {"User-Agent": "Mozilla/5.0 (compatible; Brauna-Mesas/1.0)", "Accept": "application/json"}
    url = f"https://query1.finance.yahoo.com/v8/finance/chart/{sym_full}?range=1d&interval=1d"
    try:
        with _ur.urlopen(_ur.Request(url, headers=HEAD), timeout=4) as r:
            raw = _j.loads(r.read().decode("utf-8"))
        meta = raw["chart"]["result"][0]["meta"]
        prc  = meta.get("regularMarketPrice") or meta.get("chartPreviousClose")
        prev = meta.get("previousClose") or meta.get("chartPreviousClose") or prc
        if not prc or not prev:
            return None
        return {"preco": round(float(prc), 2), "variacao": round((prc/prev - 1)*100, 2)}
    except Exception:
        return None

def _ia_disponivel() -> bool:
    """True se a ANTHROPIC_API_KEY estiver configurada (habilita curadoria por IA)."""
    import os as _os
    return bool(_os.environ.get("ANTHROPIC_API_KEY"))

_FUND_NOISE = {"FIC","FIF","FIRF","FIM","FIA","FI","FIP","RL","LP","CP","CIC","RF","SIMPLES",
    "MULTI","CLASSE","FII","CREDITO","PRIVADO","LONGO","PRAZO","SEG","PREV","FICFIM","QUALIFICADO",
    "MASTER","RESP","LIMITADA","A","B","C","DE","DO","DA","E","EM","II","III"}

def _nome_fundo_query(nome: str) -> str:
    """Reduz o nome legal de um fundo a gestora+estratégia (query de notícia menos ruidosa)."""
    import re as _re
    toks = _re.findall(r"[A-Za-zÀ-ú0-9]+", nome or "")
    sig = [t for t in toks if t.upper() not in _FUND_NOISE and len(t) > 1]
    return " ".join(sig[:3]) if sig else (nome or "").strip()

def _holdings_assessor(assessor: str, incluir_fundos: bool = False) -> dict:
    """Mapa dos ativos presentes nas carteiras dos clientes do assessor.
    Retorna {chave: {"nome":str, "query":str, "tipo":"acao|fii|fundo", "holders":set(nomes)}}.
    Ações/FIIs são chaveados por ticker; fundos (rf_ativos, exceto RF pura) por nome-query."""
    assessor = (assessor or "").lower().strip()
    fichas = load_fichas()
    hold = {}
    # Classes de rf_ativos que são fundos de gestão (têm notícia útil); RF pura fica de fora
    FUNDO_CLS = {"multimercado", "alternativos", "internacional", "acoes_fundo", "cripto_fundo"}
    for f in fichas.values():
        if not isinstance(f, dict):
            continue
        if f.get("assessor", "").lower().strip() != assessor:
            continue
        nome_cli = (f.get("nome", "") or ("#" + str(f.get("conta", "")))).strip()
        for tipo, lista in (("acao", f.get("acoes", [])), ("fii", f.get("fiis", []))):
            for a in (lista or []):
                tk = (a.get("ticker", "") or "").upper().strip()
                if not tk:
                    continue
                h = hold.setdefault(tk, {"nome": a.get("nome", ""), "query": tk, "tipo": tipo, "holders": set()})
                if a.get("nome") and not h["nome"]:
                    h["nome"] = a.get("nome")
                h["holders"].add(nome_cli)
        if incluir_fundos:
            for a in (f.get("rf_ativos", []) or []):
                if (a.get("classe", "") or "").lower() not in FUNDO_CLS:
                    continue
                nome_f = (a.get("nome", "") or "").strip()
                q = _nome_fundo_query(nome_f)
                if len(q) < 4:
                    continue
                chave = "F:" + q.upper()
                h = hold.setdefault(chave, {"nome": nome_f, "query": q, "tipo": "fundo", "holders": set()})
                h["holders"].add(nome_cli)
    return hold

def _google_news(query: str, limit: int = 2, dias_max: int = 12) -> list:
    """Manchetes recentes do Google News RSS para uma query. Sem auth."""
    import urllib.request as _ur, urllib.parse as _up, re as _re, ssl as _ssl
    import html as _html, email.utils as _eu, datetime as _dt
    ctx = _ssl.create_default_context(); ctx.check_hostname = False; ctx.verify_mode = _ssl.CERT_NONE
    HEAD = {"User-Agent": "Mozilla/5.0 (compatible; Brauna-Mesas/1.0)"}
    url = "https://news.google.com/rss/search?q=" + _up.quote(query) + "&hl=pt-BR&gl=BR&ceid=BR:pt-419"
    out = []
    try:
        with _ur.urlopen(_ur.Request(url, headers=HEAD), timeout=6, context=ctx) as r:
            raw = r.read().decode("utf-8", "ignore")
    except Exception:
        return out
    for it in _re.findall(r"<item>(.*?)</item>", raw, _re.S):
        tt = _re.search(r"<title>(.*?)</title>", it, _re.S)
        ln = _re.search(r"<link>(.*?)</link>", it, _re.S)
        pd = _re.search(r"<pubDate>(.*?)</pubDate>", it, _re.S)
        if not tt:
            continue
        titulo = _html.unescape(tt.group(1)).strip()
        fonte = ""
        if " - " in titulo:
            titulo, fonte = titulo.rsplit(" - ", 1)
        data_txt = ""
        if pd:
            try:
                dtp = _eu.parsedate_to_datetime(pd.group(1))
                if (_dt.datetime.now(dtp.tzinfo) - dtp).days > dias_max:
                    continue
                data_txt = dtp.strftime("%d/%m")
            except Exception:
                pass
        out.append({"titulo": titulo.strip(), "fonte": fonte.strip(),
                    "data": data_txt, "link": (ln.group(1).strip() if ln else "")})
        if len(out) >= limit:
            break
    return out

@app.route("/api/radar-noticias", methods=["GET"])
def radar_noticias():
    """Radar de notícias dos ativos que os clientes do assessor têm em carteira.
    Prioriza os ativos com mais clientes. Cache por assessor (3h)."""
    import time as _t
    from concurrent.futures import ThreadPoolExecutor
    assessor = request.args.get("assessor", "").lower().strip()
    if not assessor:
        return jsonify({"itens": [], "ia": _ia_disponivel()})
    cache = radar_noticias.__dict__.setdefault("_cache", {})
    ce = cache.get(assessor)
    if ce and (_t.time() - ce["ts"] < 3600):   # refresh de hora em hora
        return jsonify(ce["data"])

    hold = _holdings_assessor(assessor, incluir_fundos=True)
    itens_rv  = [kv for kv in hold.items() if kv[1]["tipo"] in ("acao", "fii")]
    itens_fnd = [kv for kv in hold.items() if kv[1]["tipo"] == "fundo"]
    itens_rv.sort(key=lambda kv: len(kv[1]["holders"]), reverse=True)
    itens_fnd.sort(key=lambda kv: len(kv[1]["holders"]), reverse=True)
    ranked = itens_rv[:12] + itens_fnd[:5]   # RV/FII em foco + poucos fundos

    def _fetch(item):
        chave, info = item
        nome = (info.get("nome") or "").strip()
        tipo = info["tipo"]
        if tipo == "fundo":
            rotulo = info.get("query") or nome
            q = info.get("query") or nome
            nots = _google_news(q, limit=2, dias_max=30)   # fundo: notícia mais esparsa
        else:
            rotulo = chave  # ticker
            q = chave + ((" " + nome.split()[0]) if nome else "")
            nots = _google_news(q, limit=2)
        return {"ticker": rotulo, "tipo": tipo, "nome": nome,
                "holders": sorted(info["holders"])[:12], "n_holders": len(info["holders"]),
                "noticias": nots}

    itens = []
    try:
        with ThreadPoolExecutor(max_workers=12) as ex:
            for res in ex.map(_fetch, ranked):
                if res["noticias"]:
                    itens.append(res)
    except Exception:
        pass

    data = {"itens": itens, "atualizado": agora_br().strftime("%d/%m %H:%M"), "ia": _ia_disponivel()}
    cache[assessor] = {"ts": _t.time(), "data": data}
    return jsonify(data)

@app.route("/api/cotacoes", methods=["GET"])
def cotacoes_endpoint():
    """Cotações em tempo real (preço + variação do dia) para tickers B3.
    Ex.: /api/cotacoes?tickers=PETR4,VALE3 — usado na proteção de posições acima do alvo."""
    raw = request.args.get("tickers", "") or ""
