@app.route("/api/hp/publicar", methods=["POST"])
def hp_publicar():
    body = request.get_json()
    portfolios = body.get("portfolios")
    cenario    = body.get("cenario")
    produtos   = body.get("produtos")
    # Salva os 3 em paralelo para reduzir latência de rede com Redis
    import threading
    erros = []
    def _s(path, data):
        try:
            _save(path, data)
        except Exception as e:
            erros.append(str(e))
    threads = []
    # Só salva portfolios se vier com alocação válida — evita zerar o modelo por engano
    if portfolios and _portfolios_validos(portfolios):
        threads.append(threading.Thread(target=_s, args=(_HP_PORT_FILE, portfolios)))
    if cenario:    threads.append(threading.Thread(target=_s, args=(_HP_CENARIO_FILE, cenario)))
    # Só salva produtos se vier com ao menos um item — evita zerar todos os produtos
    # por um 'Publicar' feito sem os produtos carregados na tela.
    if produtos and any(isinstance(v, list) and len(v) > 0 for v in produtos.values()):
        threads.append(threading.Thread(target=_s, args=(_HP_PROD_FILE, produtos)))
    for t in threads: t.start()
    for t in threads: t.join(timeout=8)
    return jsonify({"ok": True, "publicado_em": agora_br().strftime("%d/%m/%Y %H:%M")})

@app.route("/api/hp/alertas", methods=["GET","POST","DELETE"])
def hp_alertas():
    if request.method == "GET":
        return jsonify(_load(_HP_ALERTS_FILE, []))
    if request.method == "DELETE":
        data = request.get_json()
        alertas = _load(_HP_ALERTS_FILE, [])
        id_del = data.get("id")
        alertas = [a for a in alertas if a.get("id") != id_del]
        _save(_HP_ALERTS_FILE, alertas)
        return jsonify({"ok": True})
    # POST — novo alerta manual ou automático
    data = request.get_json()
    alertas = _load(_HP_ALERTS_FILE, [])
    novo = {
        "id": str(uuid.uuid4())[:8],
        "produto":    data.get("produto",""),
        "classe":     data.get("classe",""),
        "tipo":       data.get("tipo","info"),  # info | atencao | urgente
        "mensagem":   data.get("mensagem",""),
        "origem":     data.get("origem","Head de Produtos"),
        "data":       agora_br().strftime("%d/%m/%Y %H:%M"),
        "lido":       False,
        "assessor_destino": data.get("assessor_destino", ""),  # "" = global, "lucas" = só Lucas
    }
    alertas.insert(0, novo)
    alertas = alertas[:100]
    _save(_HP_ALERTS_FILE, alertas)
    # Dispara notificações individuais para cada ativo identificável.
    # Casa o campo 'produto' E todos os tickers citados no texto (troca/recado com vários papéis).
    produto = novo.get("produto","").strip()
    alvos = []
    if produto:
        alvos.append(produto)
    for tk in _tickers_no_texto(f"{produto} {novo.get('mensagem','')}"):
        if tk.upper() != produto.upper():
            alvos.append(tk)
    vistos_alvo = set()
    for alvo in alvos:
        chave = alvo.upper().strip()
        if chave in vistos_alvo:
            continue
        vistos_alvo.add(chave)
        _disparar_notificacoes_ativo(
            alvo,
            "alerta",
            f"Head de Produtos [{novo['tipo'].upper()}] {alvo}: {novo['mensagem'][:120]}",
            novo["id"],
        )
    return jsonify({"ok": True, "alerta": novo})

@app.route("/api/hp/calls", methods=["GET","POST"])
def hp_calls():
    if request.method == "GET":
        return jsonify(_load(_HP_CALLS_FILE, []))
    # POST — adicionar ou remover call
    data = request.get_json()
    if data.get("id") and data.get("_delete"):
        calls = _load(_HP_CALLS_FILE, [])
        calls = [c for c in calls if c.get("id") != data["id"]]
        _save(_HP_CALLS_FILE, calls)
        return jsonify({"ok": True})
    # Novo call
    entrada = float(data.get("preco_entrada") or 0)
    alvo    = float(data.get("preco_alvo") or 0)
    upside  = round((alvo / entrada - 1) * 100, 1) if entrada > 0 else 0
    novo = {
        "id":            str(uuid.uuid4())[:8],
        "ticker":        data.get("ticker","").upper().strip(),
        "nome":          data.get("nome",""),
        "direcao":       data.get("direcao","compra"),  # compra | venda | neutro
        "preco_entrada": entrada,
        "preco_alvo":    alvo,
        "upside":        upside,
        "stop":          float(data.get("stop") or 0),
        "prazo":         data.get("prazo",""),
        "tese":          data.get("tese",""),
        "perfis":        data.get("perfis", []),
        "fonte":         data.get("fonte",""),
        "data":          agora_br().strftime("%d/%m/%Y"),
        "ativo":         True,
    }
    calls = _load(_HP_CALLS_FILE, [])
    calls.insert(0, novo)
    calls = calls[:200]
    _save(_HP_CALLS_FILE, calls)
    # Notifica cada assessor que tenha clientes com o ativo OU perfil compatível
    afetados = _notificar_call_nova(novo)
    return jsonify({"ok": True, "call": novo, "assessores_notificados": list(afetados.keys())})

def _tickers_no_texto(texto: str) -> list:
    """Extrai tickers B3 (ex.: PETR4, BBAS3, KNRI11) de um texto livre.
    Filtra falsos positivos comuns (siglas sem pregão)."""
    if not texto:
        return []
    import re as _re
    achados = _re.findall(r"\b([A-Z]{4}\d{1,2})\b", texto.upper())
    FALSOS = {"COVID19", "IBOV11"}  # ruídos improváveis de serem posição
    out, vistos = [], set()
    for t in achados:
        if t in FALSOS or t in vistos:
            continue
        vistos.add(t); out.append(t)
    return out

def _disparar_notificacoes_ativo(ticker_ou_nome: str, tipo: str, mensagem: str, item_id: str):
    """
    Varre todas as fichas e cria notificações para assessores
    cujos clientes possuem o ativo informado.
    ticker_ou_nome: ticker (ex: 'BBAS3') ou nome parcial de RF (ex: 'Tesouro IPCA')
    tipo: 'call' | 'alerta'
    """
    fichas = load_fichas()
    notif  = _load(_NOTIF_FILE, {})
    busca  = ticker_ou_nome.upper().strip()

    por_assessor = {}  # assessor → [nome_cliente, ...]
    vistos = set()     # evita duplicar por ter duas chaves para o mesmo cliente

    for ficha in fichas.values():
        if not isinstance(ficha, dict):
            continue
        cliente_id = ficha.get("conta") or (ficha.get("assessor","")+"_"+ficha.get("nome",""))
        if cliente_id in vistos:
            continue
        assessor    = ficha.get("assessor","").strip()
        nome_cli    = ficha.get("nome","").strip()
        if not assessor or not nome_cli:
            continue

        # Verifica ações e FIIs (match por ticker exato)
        encontrou = any(
            a.get("ticker","").upper() == busca
            for a in (ficha.get("acoes",[]) + ficha.get("fiis",[]))
        )
        # Verifica RF (match parcial no nome)
        if not encontrou:
            encontrou = any(
                busca in a.get("nome","").upper()
                for a in ficha.get("rf_ativos",[])
            )

        if encontrou:
            vistos.add(cliente_id)
            if assessor not in por_assessor:
                por_assessor[assessor] = []
            por_assessor[assessor].append(nome_cli)

    agora = agora_br().strftime("%d/%m/%Y %H:%M")
    for assessor, clientes in por_assessor.items():
        if assessor not in notif:
            notif[assessor] = []
        notif[assessor].insert(0, {
            "id":               item_id,
            "tipo":             tipo,           # 'call' | 'alerta'
            "ticker":           ticker_ou_nome,
            "mensagem":         mensagem,
            "clientes_afetados": clientes,
            "data":             agora,
            "lido":             False,
        })
        notif[assessor] = notif[assessor][:50]  # últimas 50 por assessor

    _save(_NOTIF_FILE, notif)
    return por_assessor   # retorna para log/resposta

@app.route("/api/minhas-notificacoes", methods=["GET","POST"])
def minhas_notificacoes():
    assessor = (request.args.get("assessor","") or "").strip().lower()
    notif    = _load(_NOTIF_FILE, {})

    if request.method == "POST":
        # Marcar como lido: {"assessor":"...", "id":"...", "all":true}
        d = request.get_json() or {}
        ass = d.get("assessor","").strip()
        if ass in notif:
            if d.get("all"):
                for n in notif[ass]:
                    n["lido"] = True
            else:
                nid = d.get("id","")
                for n in notif[ass]:
                    if n["id"] == nid:
                        n["lido"] = True
            _save(_NOTIF_FILE, notif)
        return jsonify({"ok": True})

    # GET — retorna notificações do assessor (match case-insensitive)
    for key in notif:
        if key.lower() == assessor:
            return jsonify(notif[key])
    # Tenta match parcial (primeiro nome)
    primeiro = assessor.split()[0] if assessor else ""
    for key in notif:
        if primeiro and key.lower().startswith(primeiro):
            return jsonify(notif[key])
    return jsonify([])

# ── Calls do Head × carteira do assessor (proativo) ──────────────────────────
# Régua de risco dos perfis: uma call de RV mirando "arrojada/agressiva" também
# é compatível com clientes de perfil igual ou MAIS agressivo (nunca menos).
_PERFIL_RANK = {
    "super_conservadora": 0, "super conservadora": 0,
    "conservadora": 1, "moderada": 2, "arrojada": 3, "agressiva": 4,
}

def _norm_assessor_key(nome):
    """Espelha o normAssessorKey do front: 'primeiro|ultimo' sem acento, minúsculo."""
    import unicodedata
    s = unicodedata.normalize("NFKD", str(nome or "")).encode("ascii", "ignore").decode().lower().strip()
    s = " ".join(s.split())
    if not s:
        return ""
    p = [x for x in s.split(" ") if x]
    return p[0] if len(p) <= 1 else p[0] + "|" + p[-1]

def _perfil_rank(perfil):
    p = str(perfil or "").lower().strip()
    if p in _PERFIL_RANK:
        return _PERFIL_RANK[p]
    for k, v in _PERFIL_RANK.items():
        if k and k in p:
            return v
    return None

def _perfil_compativel_call(perfil_cliente, call_perfis):
    """Cliente é compatível se o perfil dele alcança (>=) o perfil-alvo menos
    agressivo da call. Sem perfis-alvo definidos, a call vale para todos."""
    if not call_perfis:
        return True
    ranks = [_perfil_rank(p) for p in call_perfis]
    ranks = [r for r in ranks if r is not None]
    pr = _perfil_rank(perfil_cliente)
    if pr is None or not ranks:
        # Fallback textual quando não dá para ranquear
        pc = str(perfil_cliente or "").lower()
        return any(str(p or "").lower() in pc for p in call_perfis if p)
    return pr >= min(ranks)

def _coletar_clientes_assessor(assessor_nome):
    """Todos os clientes do assessor (dedup por conta), com perfil e os tickers
    (ações+FIIs) da última carteira salva no histórico."""
    ass_key = _norm_assessor_key(assessor_nome)
    ass_low = (assessor_nome or "").lower().strip()
    fichas  = load_fichas()
    hist    = load_hist()
    clientes, seen = [], set()
    for k, v in fichas.items():
        if not isinstance(v, dict):
            continue
        v_ass = str(v.get("assessor", "") or "")
        if not (_norm_assessor_key(v_ass) == ass_key
                or k.startswith(ass_low + "|")
                or v_ass.lower().strip() == ass_low):
            continue
        conta = str(v.get("conta", "")).strip()
        dedup = conta or k
        if dedup in seen:
            continue
        seen.add(dedup)
        perfil = (v.get("perfil", "") or "").lower().strip()

        # Posições da carteira mais recente que tenha ações/FIIs
        hentry = None
        if conta:
            hentry = hist.get(f"conta:{conta}") or hist.get(conta)
        if hentry is None:
            hentry = hist.get(k)
        ents = hentry.get("entradas") if isinstance(hentry, dict) else hentry
        tickers = set()
        if isinstance(ents, list):
            for e in reversed(ents):
                if not isinstance(e, dict):
                    continue
                pos = (e.get("acoes") or []) + (e.get("fiis") or [])
                if pos:
                    for a in pos:
                        t = str((a or {}).get("ticker", "")).upper().strip()
                        if t:
                            tickers.add(t)
                    break
        clientes.append({"conta": conta, "nome": v.get("nome", ""),
                         "perfil": perfil, "tickers": tickers})
    return clientes

def _match_call_clientes(call, clientes):
    """Clientes que (a) detêm o ticker da call ou (b) têm perfil compatível.
    Detentores primeiro."""
    tk = str(call.get("ticker", "")).upper().strip()
    perfis = call.get("perfis") or []
    detem, compat = [], []
    for c in clientes:
        tem = bool(tk) and tk in c["tickers"]
        comp = _perfil_compativel_call(c["perfil"], perfis)
        if not (tem or comp):
            continue
        item = {"conta": c["conta"], "nome": c["nome"], "perfil": c["perfil"],
                "detem": tem, "perfil_compativel": comp}
        (detem if tem else compat).append(item)
    return detem + compat

def _notificar_call_nova(call):
    """Cria uma notificação por assessor cujos clientes casam com a call nova."""
    fichas = load_fichas()
    assessores = {}  # chave normalizada → nome de exibição
    for v in fichas.values():
        if isinstance(v, dict) and str(v.get("assessor", "") or "").strip():
            nome = str(v.get("assessor")).strip()
            assessores.setdefault(_norm_assessor_key(nome), nome)

    notif = _load(_NOTIF_FILE, {})
    agora = agora_br().strftime("%d/%m/%Y %H:%M")
    direc = str(call.get("direcao", "") or "").upper()
    afetados = {}
    for ass_nome in assessores.values():
        matched = _match_call_clientes(call, _coletar_clientes_assessor(ass_nome))
        if not matched:
            continue
        n = len(matched)
        n_detem = sum(1 for m in matched if m["detem"])
        nomes = [(m["nome"] or ("#" + (m["conta"] or ""))) for m in matched][:12]
        msg = (f"Nova call do Head: {direc} {call.get('ticker','')} — "
               f"você tem {n} cliente{'s' if n != 1 else ''} para este ativo"
               + (f" ({n_detem} já detêm)" if n_detem else ""))
        notif.setdefault(ass_nome, [])
        notif[ass_nome].insert(0, {
            "id":                call.get("id"),
            "tipo":              "call",
            "ticker":            call.get("ticker", ""),
            "mensagem":          msg,
            "clientes_afetados": nomes,
            "data":              agora,
            "lido":              False,
        })
        notif[ass_nome] = notif[ass_nome][:50]
        afetados[ass_nome] = nomes
    _save(_NOTIF_FILE, notif)
    return afetados

@app.route("/api/assessor/calls-clientes", methods=["GET"])
def assessor_calls_clientes():
    """Para o assessor logado: calls ativas do Head + para cada uma os clientes
    dele que já detêm o ticker OU têm perfil compatível com a operação."""
    assessor = (request.args.get("assessor", "") or "").strip()
    if not assessor:
        return jsonify({"assessor": "", "total_clientes": 0, "calls": []})
    calls = [c for c in _load(_HP_CALLS_FILE, []) if c.get("ativo", True)]
    clientes = _coletar_clientes_assessor(assessor)
    out = []
    for call in calls:
        matched = _match_call_clientes(call, clientes)
        out.append({
            **call,
            "clientes":  matched,
            "n_clientes": len(matched),
            "n_detem":   sum(1 for m in matched if m["detem"]),
            "n_compat":  sum(1 for m in matched if m["perfil_compativel"] and not m["detem"]),
        })
    # Mais clientes primeiro; empate mantém a ordem de publicação (mais nova no topo)
    out.sort(key=lambda c: c["n_clientes"], reverse=True)
    return jsonify({"assessor": assessor, "total_clientes": len(clientes), "calls": out})

@app.route("/api/hp/gestoras2", methods=["GET","POST"])
def hp_gestoras2():
    """Armazena carteiras de gestoras externas com os 5 perfis. Estrutura: {gestora_id: {nome, referencia, perfis:{perfil:{classe:%}}}}"""
    if request.method == "GET":
        return jsonify(_load(_HP_GESTORAS2_FILE, {}))
    data = request.get_json()
    if data.get("_delete"):
        gestoras = _load(_HP_GESTORAS2_FILE, {})
        gid = data.get("id","")
        gestoras.pop(gid, None)
        _save(_HP_GESTORAS2_FILE, gestoras)
        return jsonify({"ok": True})
    CLASSES = ["pos_fixado","inflacao","pre_fixado","acoes","fiis","multimercado","internacional","alternativos","criptomoedas"]
    PERFIS  = ["super_conservadora","conservadora","moderada","arrojada","agressiva"]
    gestoras = _load(_HP_GESTORAS2_FILE, {})
    if len(gestoras) >= 5 and data.get("id","") not in gestoras:
        return jsonify({"ok": False, "error": "Máximo de 5 gestoras atingido."}), 400
    gid = data.get("id") or data.get("nome","gestora").lower().replace(" ","_")[:20]
    perfis_data = {}
    for p in PERFIS:
        alocacao = {}
        for c in CLASSES:
            v = data.get("perfis",{}).get(p,{}).get(c, 0)
            alocacao[c] = round(float(v or 0), 1)
        perfis_data[p] = alocacao
    gestoras[gid] = {"id": gid, "nome": data.get("nome","").strip(), "referencia": data.get("referencia","").strip(), "perfis": perfis_data}
    _save(_HP_GESTORAS2_FILE, gestoras)
    return jsonify({"ok": True, "id": gid})

