# ── Retornos por classe (líder cadastra) → base do comparativo de rentabilidade ─
_RET_CLASSES = ["pos_fixado","inflacao","pre_fixado","acoes","fiis","multimercado","internacional","alternativos","criptomoedas"]
_RET_PERIODOS = ["mes","ano","12m","24m"]
_RET_LABELS = {"pos_fixado":"Pós Fixado","inflacao":"Inflação","pre_fixado":"Pré Fixado","acoes":"Ações",
               "fiis":"FIIs","multimercado":"Multimercado","internacional":"Internacional",
               "alternativos":"Alternativos","criptomoedas":"Criptomoedas"}

def carregar_retornos():
    salvo = _load(_RETORNOS_FILE, None)
    base = {"classes": {c: {p: None for p in _RET_PERIODOS} for c in _RET_CLASSES}, "atualizado_em": ""}
    if isinstance(salvo, dict) and isinstance(salvo.get("classes"), dict):
        for c in _RET_CLASSES:
            row = salvo["classes"].get(c) or {}
            for p in _RET_PERIODOS:
                if p in row:
                    base["classes"][c][p] = row[p]
        base["atualizado_em"] = salvo.get("atualizado_em","")
    base["_meta"] = {"classes": _RET_CLASSES, "periodos": _RET_PERIODOS, "labels": _RET_LABELS}
    return base

def agregar_retornos_classe():
    """Média ponderada por saldo do retorno realizado de cada classe, entre os
    snapshots mais recentes de todos os clientes salvos. Fonte 'auto' (média da casa)
    do comparativo de rentabilidade, extraída dos XPerformance importados."""
    hist = load_hist()
    acc = {c: {p: [0.0, 0.0] for p in _RET_PERIODOS} for c in _RET_CLASSES}
    n_cli = 0
    for reg in (hist.values() if isinstance(hist, dict) else []):
        if not isinstance(reg, dict):
            continue
        ents = reg.get("entradas") or []
        rc = (ents[0] or {}).get("ret_classe") if ents and isinstance(ents[0], dict) else None
        if not rc or not isinstance(rc, dict):
            continue
        contou = False
        for cls, dd in rc.items():
            if cls not in acc or not isinstance(dd, dict):
                continue
            saldo = dd.get("saldo") or 0
            if saldo <= 0:
                continue
            for p in _RET_PERIODOS:
                v = dd.get(p)
                if v is None:
                    continue
                acc[cls][p][0] += saldo
                acc[cls][p][1] += saldo * v
                contou = True
        if contou:
            n_cli += 1
    out = {c: {p: (round(acc[c][p][1] / acc[c][p][0], 2) if acc[c][p][0] > 0 else None)
               for p in _RET_PERIODOS} for c in _RET_CLASSES}
    return {"classes": out, "n_clientes": n_cli}


def _retornos_payload():
    """Monta o payload do comparativo: valores EFETIVOS (override manual da liderança
    quando houver, senão a média da casa) + as duas camadas separadas para a UI."""
    manual = carregar_retornos()
    auto = agregar_retornos_classe()
    man_cls = manual.get("classes", {})
    aut_cls = auto.get("classes", {})
    efetivo = {}
    for c in _RET_CLASSES:
        efetivo[c] = {}
        for p in _RET_PERIODOS:
            mv = (man_cls.get(c) or {}).get(p)
            av = (aut_cls.get(c) or {}).get(p)
            efetivo[c][p] = mv if mv is not None else av
    return {
        "classes": efetivo,      # merged — o gráfico Cliente × Recomendada × CDI lê isto
        "_manual": man_cls,      # override da liderança (valor dos inputs no Líder)
        "_auto": aut_cls,        # média realizada da casa (placeholder / fallback)
        "_n_clientes": auto.get("n_clientes", 0),
        "_meta": manual.get("_meta", {"classes": _RET_CLASSES, "periodos": _RET_PERIODOS, "labels": _RET_LABELS}),
        "atualizado_em": manual.get("atualizado_em", ""),
    }


@app.route("/api/retornos-classe", methods=["GET", "POST"])
def api_retornos_classe():
    """Retorno (%) por classe e período. Fonte automática = média da casa extraída
    dos XPerformance; a liderança pode sobrescrever qualquer célula (override manual)."""
    if request.method == "GET":
        return jsonify(_retornos_payload())
    d = request.get_json() or {}
    atual = carregar_retornos()
    cls_in = d.get("classes", {}) or {}
    for c in _RET_CLASSES:
        row = cls_in.get(c) or {}
        for p in _RET_PERIODOS:
            if p in row:
                v = row[p]
                try:
                    atual["classes"][c][p] = float(v) if v not in (None, "") else None
                except Exception:
                    atual["classes"][c][p] = None
    atual["atualizado_em"] = agora_br().strftime("%d/%m/%Y %H:%M")
    _save(_RETORNOS_FILE, {"classes": atual["classes"], "atualizado_em": atual["atualizado_em"]})
    return jsonify({"ok": True, "retornos": _retornos_payload()})

@app.route("/api/objetivos", methods=["GET", "POST"])
def api_objetivos():
    """Objetivos/OKR por assessor. As 5 classes guardam o volume financeiro (R$)
    a operar no mês; a receita é derivada por volume × ROA (ROA fixo no _meta)."""
    if request.method == "GET":
        return jsonify(carregar_objetivos())
    d = request.get_json() or {}
    atual = carregar_objetivos()
    _CLS = ("RF", "RV", "FII", "internacional", "estruturadas")
    # Aceita lista de assessores editados; mescla por nome, preservando o restante
    editados = {str(a.get("assessor", "")).strip(): a for a in (d.get("assessores", []) or [])}
    for a in atual.get("assessores", []):
        nome = str(a.get("assessor", "")).strip()
        if nome not in editados:
            continue
        e = editados[nome]
        if "okr_mensal" in e:
            try:
                a["okr_mensal"] = float(e["okr_mensal"]) if e["okr_mensal"] not in (None, "") else None
            except Exception:
                pass
        cls_in = e.get("classes", {}) or {}
        a.setdefault("classes", {})
        for k in _CLS:
            if k in cls_in:
                v = cls_in[k]
                try:
                    a["classes"][k] = float(v) if v not in (None, "") else None
                except Exception:
                    a["classes"][k] = None
        real_in = e.get("realizado", {}) or {}
        a.setdefault("realizado", {})
        for k in _CLS:
            if k in real_in:
                v = real_in[k]
                try:
                    a["realizado"][k] = float(v) if v not in (None, "") else None
                except Exception:
                    a["realizado"][k] = None
    atual.setdefault("_meta", {})["atualizado_em"] = agora_br().strftime("%d/%m/%Y %H:%M")
    _save(_OBJETIVOS_FILE, atual)
    return jsonify({"ok": True, "objetivos": atual})

